import Vue from 'vue'
import App from './App.vue'
import router from './router'
import store from './store'
import mixin from '@/components/mixin'

Vue.config.productionTip = false

import ApiWorker from 'worker-loader!./worker.js'
window.worker = new ApiWorker()

Vue.mixin(mixin)

new Vue({
	router,
	store,
	render: h => h(App),
	data: { },
	mounted() {
		window.worker.addEventListener('message', ev => {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				//Пользователь залогинился
				case 'login':
					if (ev.data.result && ev.data.result == 'fail') {
						store.dispatch('deleteToken')
						store.dispatch('clearUserData')
						router.push('auth')
					}
					break

				// Сервер выдал новый токен
				case 'newtoken':
					if (ev.data.token && ev.data.token.length)
						store.setNewToken(ev.data.token)
					break
			}
		}, false)
	}
}).$mount('main')