<template>
	<!-- ctrl+alt+"\" обновляет записи -->
	<div class="body">
		<div class="header">Цены Ашана</div>
		<div class="filterline">
			<div>
				<div :class="{loadArea: true, disabled: pendingUpload}">Загрузить файл с ценами
					<input type="file" ref="pricesFile" @change="loadFile" :disabled="pendingUpload">
				</div>
				<progress v-if="pendingUpload"></progress>
			</div>
		</div>
	</div>
</template>

<script>
import pager from '@/components/pager'
import filterBlock from '@/components/filterBlock'
export default {
	components: {pager, filterBlock},
	created() {
		this.clearFilters('init')
		this.$store.dispatch('setLastPage', this.type)
	},
	data() {
		return {
			type: 'prices',
			page: 1,
			prices: [],
			filters: null,

			filterFields: [
				{
					type: 'reset',
					value: 'Очистить фильтры',
					width: 2,
					row: 1
				},
				{
					type: 'submit',
					value: 'Применить',
					width: 2,
					row: 1
				}
			],
			pendingUpload: false
		}
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))

		if (!this.uRoles.length || !this.linksToDraw[this.type]) {
			location.hash = '#/splash'
			return
		}

		this.refreshList()

		window.addEventListener('keyup', this.keyHandler, false)
		window.worker.addEventListener('message', this.workerHandler)
	},

	beforeDestroy() {
		window.removeEventListener('keyup', this.keyHandler)
		window.worker.removeEventListener('message', this.workerHandler)
	},

	methods: {
		keyHandler(E) {
			let M

			if (E.code == 'Backslash' && E.ctrlKey && E.altKey && !E.shiftKey)
				this.refreshList()

			else if (E.ctrlKey && E.shiftKey && !E.altKey && (M = E.code.match(/^(?:Numpad|Digit)([0-9])$/))) {
				if (M[1] > 0)
					this.page = parseInt(M[1])
			}
		},

		workerHandler(ev) {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				case 'pricesLoaded': case 'badImportPrices':
					this.pendingUpload = false
					break
			}
		},

		refreshList(resetPage) {
			if (this.token) {
				this.prices = []

				if (resetPage !== undefined && this.page !== 1)
					this.page = 1
				else
					window.worker.postMessage({
						type: this.type,
						page: this.page,
						pageSize: this.pageSize,
						token: this.token,
						filters: this.filters
					})
			}
		},

		clearFilters(init) {
			this.filters = {
				a: ''
			}

			if (init == undefined)
				this.refreshList()
		},

		setFilter(data) {
			this.filters = Object.assign(this.filters, data)

			this.refreshList('resetPage')
		},

		// Загрузка файла с ценами
		loadFile(E) {
			this.pendingUpload = true

			const file = new FileReader()
			file.onload = () => {
				window.worker.postMessage({
					type: 'loadFilePrices',
					token: this.token,
					file: file.result
				})
			}
			file.readAsArrayBuffer(E.target.files[0])
		}
	},

	watch: {
		token(newToken) {
			if (newToken !== null && this.uRoles.length && this.refreshList)
				this.refreshList()
		},

		page() {
			this.refreshList()
		}
	}
}
</script>

