<template>
	<div :class="{MainBody: true, withAside}">
		<div :class="{TopPanel: true, withAside}" v-if="withTopPanel">
			<span class="logo"><img src="@/assets/img/logo.svg" alt="Лого"></span>
			<span class="role" @click="getUserInfo" title="Обновить данные">{{ userRoles.join(', ') }}</span>
			<span class="name" @click="getUserInfo" title="Обновить данные">{{ userName }}</span>
			<a href="#" @click="logout" class="exit" title="[Alt + F10]">Выйти</a>
		</div>
		<router-view/>
		<aside v-if="withAside">
			<div class="logo"><img src="@/assets/img/logo.svg" alt="Лого"><span>GTS Monitoring</span></div>
			<nav>
				<router-link to="records" v-if="linksToDraw.records" :class="{records: true}"><span>Записи</span></router-link>
				<router-link to="sku"     v-if="linksToDraw.sku"     :class="{sku: true}"><span>Sku</span></router-link>
				<router-link to="waves"   v-if="linksToDraw.waves"   :class="{waves: true}"><span>Волны</span></router-link>
				<router-link to="chat"    v-if="linksToDraw.chat"    :class="{chat: true}"><span>Чат</span></router-link>
				<router-link to="charts"  v-if="linksToDraw.charts"  :class="{charts: true}"><span>Аналитика</span></router-link>
				<router-link to="users"   v-if="linksToDraw.users"   :class="{users: true}"><span>{{ userLinkName }}</span></router-link>
				<router-link to="prices"  v-if="linksToDraw.prices"  :class="{prices: true}"><span>Цены Ашана</span></router-link>
			</nav>
		</aside>
	</div>
</template>

<script>
export default {
	data() {
		return { }
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))

		if (!this.$store.getters.getToken) {
			this.$router.push('/auth')
			return
		}
		else
			this.getUserInfo()

		window.worker.addEventListener('message', ev => {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				case 'userInfo':
					if ('user' in ev.data)
						this.$store.dispatch('setUserData', ev.data.user)
					break

				// Цены Ашана загружены
				case 'pricesLoaded':
					alert('Цены Ашана загружены')
					break

				// Ошибка загрузки цен Ашана
				case 'badImportPrices':
					alert('Не удалось загрузить цены Ашана')
					break
			}
		})

		window.addEventListener('keydown', E => {
			let M
			if (E.ctrlKey && !E.altKey && !E.shiftKey && (M = E.code.match(/^(?:Numpad|Digit)([0-9]$)/))) {
				this.gotoNthLink(parseInt(M[1]))
			}

			if (E.code == 'F10' && E.altKey && !E.ctrlKey && !E.shiftKey)
				this.logout()
		}, false)
	},

	computed: {
		userRoles()    { return this.$store.getters.getUserRoles },
		userName()     { return this.$store.getters.getUserName },
		withTopPanel() { return this.$route.name != 'auth' },
		withAside()    { return this.$route.name != 'auth' },
		userLinkName() { return this.hasOnlyRole('admin') ? 'Пользователи' : 'Аудиторы' }
	},

	methods: {
		logout() {
			this.$store.dispatch('deleteToken')
			this.$store.dispatch('clearUserData')
			this.$router.push('/auth')
		},

		getUserInfo() {
			this.$store.dispatch('clearUserData')
			window.worker.postMessage({
				type: 'userInfo',
				token: this.$store.getters.getToken
			})
		},

		// Переход к N-му пункту меню
		gotoNthLink(N) {
			let c = 0
			const vu = this
			const keys = ['records', 'sku', 'waves', 'chat', 'charts', 'users', 'prices']

			for (let z in keys) {
				if (c >= N) continue
				if (vu.linksToDraw[keys[z]] == true) c++
				else continue

				if (c == N)
					vu.$router.push(`/${keys[z]}`)
			}
		}
	}
}
</script>


