<template>
	<input type="text" :class="{inputField: true, oldPrice: oldPrice == 'true', textField}" @change="emitChange" @keydown="emitDown" @keyup="emitUp" v-model="Value" :list="'prod' + idx"/>
</template>

<script>
	export default {
		props: ['value', 'oldPrice', 'textField', 'idx'],

		data() {
			return {
				Value: 0
			}
		},

		created() {
			this.Value = this.value || ''
		},

		methods: {
			emitChange() {
				this.$emit('change', this.valueNumber)
			},

			emitUp(ev) {
				this.$emit('keyup', ev)
			},

			emitDown(ev) {
				this.$emit('keydown', ev)
			}
		},

		computed: {
			valueNumber() {
				if (this.textField)
					return this.Value

				if (this.Value === null) return ''

				let ret = this.Value.toString()
					.replace(/[^0-9.,]/, '')        // Только цифры и разделитель
					.replace(',', '.')              // Сервер просит разделитель-точку
					.replace(/\.(\d\d).+$/, '.$1')  // Дробная часть не больше двух знаков
					.replace(/^(\d*?\.\d*?)\..*$/, '$1') // Дробная часть только одна
				this.Value = ret

				return ret
			}
		},

		watch: {
			Value() {
				/*if (!this.Value)
					return 0*/

				this.$emit('input', this.valueNumber)
			},

			value(V) {
				this.Value = V
			}
		}
	}
</script>

