<template>
	<form class="login" @submit="loginFormSubmit">
		<div class="row logo"><img src="@/assets/img/logo.svg" alt="Логотип"></div>
		<div class="row title">Войдите используя логин и пароль</div>
		<div class="row loginrow"><input type="text" name="login" v-model="loginForm.login" placeholder="Логин" required maxlength="10"></div>
		<div class="row"><input type="password" name="password" v-model="loginForm.password" placeholder="Пароль" required></div>
		<div class="row submit">
			<input type="submit" value="Войти" v-if="!loginInProgress">
			<progress v-else></progress>
		</div>
	</form>
 </template>

<script>
export default {
	name: 'Auth',
	data() {
		return {
			loginForm: {
				login: '',
				password: ''
			},

			loginInProgress: false
		}
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))
		if (this.$store.getters.getToken) {
			this.$router.push('/')
			return
		}

		// Установка курсора в поле с логином
		const loginInput = document.querySelector('[name=login]')
		const passInput = document.querySelector('[name=password]')
		if (loginInput) loginInput.focus()

		// Автозаполнение логина после последнего входа и установка курсора в поле с паролем
		if (localStorage.getItem('login')) {
			this.loginForm.login = localStorage.getItem('login')
			if (passInput) passInput.focus()
		}

		window.worker.addEventListener('message', this.workerHandler, false)
	},

	beforeDestroy() {
		window.worker.removeEventListener('message', this.workerHandler)
	},
	
	methods: {
		loginFormSubmit(ev) {
			ev.preventDefault()
			this.tryLogin(this.loginForm.login, this.loginForm.password)
		},

		workerHandler(ev) {
			if (!('type' in ev.data)) return

			if (ev.data.type == 'login' && ev.data.result) {
				this.loginInProgress = false

				if (ev.data.result == 'fail')
					this.loginForm.password = ''
				else {
					localStorage.setItem('login', this.loginForm.login)
					if (ev.data.token)
						this.$store.dispatch('setNewToken', ev.data.token)
					if (ev.data.user)  // Это условие обязано выполняться, но на всякий случай
						this.$store.dispatch('setUserData', ev.data.user)

					if (this.linksToDraw.records)
						this.$router.push('records')
					else
						this.$router.push('users')
				}
			}
		},

		tryLogin(login, password) {
			this.loginInProgress = true
			window.worker.postMessage({
				type: 'login',
				login: login,
				password: password
			})
		}
	}
}
</script>

