<template>
	<!-- ctrl+alt+"\" обновляет записи -->
	<div>
		<div class="body" v-show="!detailsInfo && !showAddWaveForm">
			<div class="header">Волны</div>
			<div class="filterline">
				<filterBlock :filterFields="filterFields" @reset="clearFilters" @submit="setFilter"/>
				<input type="button" class="addNew" @click="displayAddWaveForm" value="Создать волну" title="[Alt + C]" v-if="isAdmin">
			</div>
			<div class="counter-pager-submit">
				<span class="recordsCount">{{ totalWavesSTR }} волн{{ wavesWordEnd }}</span>
				<pager v-if="totalWavesCount > pageSize" :currentPage="page" :pagesCount="pagesCount" @changePage="gotoPage"/>
			</div>
			<table :class="{item: true}" v-for="(item, idx) in waves">
				<tr class="tableHeader" v-if="!idx">
					<th>Волна</th>
					<th>Дата создания</th>
					<th>Дата начала</th>
					<th>Дата окончания</th>
					<th>Клиент</th>
					<th v-if="!isAdmin">Статус</th>
				</tr>
				<tr @click="showDistributionForm(item.id)">
					<td class="name">{{ item.name }}</td>
					<td class="date">{{ convertDate(item.create_time) }}</td>
					<td class="date">{{ convertDate(item.begin) }}</td>
					<td class="date">{{ convertDate(item.end) }}</td>
					<td class="client">{{ item.customer.name }}</td>
					<td :class="{status: true, done: item.distribution_status == 'distributed'}" v-if="!isAdmin">
						<span v-if="item.distribution_status == 'distributing'">не распределён</span>
						<span v-else>распределён</span>
					</td>
				</tr>
			</table>
			<pager v-if="totalWavesCount > pageSize" :currentPage="page" :pagesCount="pagesCount" @changePage="gotoPage"/>
		</div>

		<!-- Форма добавления/редактирования -->
		<div class="body addWave" v-if="showAddWaveForm">
			<div class="header">
				<div class="backButton" @click="exitAddWaveForm" title="[Escape]"><img src="@/assets/img/back.svg">назад</div>
				<span v-if="isEditing">Редактирование волны №{{ waveInfo && waveInfo.id }}</span>
				<span v-else><span v-if="pendingAddWave">…</span><span v-else>Создание волны</span></span>
			</div>
			<progress v-if="waveInfoLoading"></progress>
			<form class="addForm addWaveForm" ref="addWaveForm">
				<div class="Fblock">
					<div class="title">Название волны</div>
					<div>
						<input type="text" v-model="addWaveForm.name">
					</div>
				</div>
				<div class="Fblock">
					<div class="title">Дата начала</div>
					<div class="date">
						<Datepicker :disabled="disableAddForm" :language="ru" format="dd.MM.yyyy" v-model="addWaveForm.dateFrom"/>
					</div>
				</div>
				<div class="Fblock">
					<div class="title">Дата окончания</div>
					<div class="date">
						<Datepicker :disabled="disableAddForm" :language="ru" format="dd.MM.yyyy" v-model="addWaveForm.dateTo"/>
					</div>
				</div>
				<div class="Fblock">
					<div class="title">Клиент</div>
					<div>
						<select v-model="addWaveForm.client" :disabled="disableAddForm">
							<option value="-1" disabled>Клиент</option>
							<option v-for="client in clientsList" :value="client.id">{{ client.name }}</option>
						</select>
					</div>
				</div>
				<div class="Fblock">
					<div class="title">&nbsp;</div>
					<div>
						<input type="button" class="submit" value="Сохранить" title="[F2]" :disabled="pendingAddWave || disableAddForm" @click="addWave">
					</div>
				</div>
			</form>
			<div class="loadFiles" v-if="isEditing">
				<div class="loadLine">
					<div :class="{tab: true, active: loadTabs.active.tabTT}" @click="changeLoadTab('tt')">
						<b>ТТ<span v-if="tradepointsList.length">{{ tradepointsList.length }}</span></b>
						<span class="load"><input type="file" @change="ttSelected"><span>{{ loadFileTT }}</span></span>
					</div>
					<div :class="{tab: true, active: loadTabs.active.tabSegments}" @click="changeLoadTab('segments')">
						<b>Сегменты<span v-if="segmentsList.length">{{ segmentsList.length }}</span></b>
						<span class="load"><input type="file" @change="segmentsSelected"><span>{{ loadFileSegments }}</span></span>
					</div>
				</div>

				<div v-show="loadTabs.active.tabTT">
					<div v-if="loadTabs.loading.tt">Файл загружается на сервер <progress></progress></div>
					<table v-if="waveInfo && waveInfo.shops">
						<tr>
							<th class="net">Сеть</th>
							<th class="address">Адрес</th>
							<th>Файл в отчёте</th>
						</tr>
						<tr v-for="shop in waveInfo.shops">
							<td>{{ shop.retail_network.name }}</td>
							<td>{{ shop.address }}</td>
							<td>{{ shop.target_file_name }}</td>
						</tr>
					</table>
				</div>

				<div v-show="loadTabs.active.tabSegments">
					<div v-if="loadTabs.loading.segments">Файл загружается на сервер <progress></progress></div>
					<table v-if="waveInfo && waveInfo.segments">
						<tr>
							<th>Сегмент</th>
						</tr>
						<tr v-for="seg in waveInfo.segments">
							<td>{{ seg.name }}</td>
						</tr>
					</table>
				</div>
			</div>
		</div>

		<!-- Форма распределения -->
		<div class="body" v-if="detailsInfo && !showAddWaveForm && !isAdmin">
			<div class="header">
				<div class="backButton" @click="exitDetails" title="[Escape]"><img src="@/assets/img/back.svg">назад</div>
				Распределение волны
			</div>
			<div class="filterline">
				<filterBlock class="wavesFilter" :filterFields="filterFieldsDetails" @reset="clearFiltersDetails" @submit="setFilterDetails"/>
			</div>
			<div v-if="!waveInfo"><progress></progress></div>
			<div class="infoBlock" v-else :key="waveInfo.id">
				<div class="infoLine">
					<div class="block"><b class="ttl">Волна</b><span :title="'№' + waveInfo.id">{{ waveInfo.name }}</span></div>
					<div class="block"><b class="ttl">Дата создания</b><span>{{ convertDate(waveInfo.create_time) }}</span></div>
					<div class="block"><b class="ttl">Дата начала</b><span>{{ convertDate(waveInfo.begin) }}</span></div>
					<div class="block"><b class="ttl">Дата окончания</b><span>{{ convertDate(waveInfo.end) }}</span></div>
					<div class="block"><b class="ttl">Клиент</b><span>{{ waveInfo.customer.name }}</span></div>
					<div :class="{block:true, status:true, done: waveInfo.distribution_status == 'distributed'}">
						<b class="ttl">Статус</b>
						<span class="bg" v-if="waveInfo.distribution_status == 'distributed'">распределён</span>
						<span class="bg" v-else>не распределён</span>
					</div>
				</div>
				<form class="addForm distribution" ref="addForm">
					<div class="Fblock">
						<div class="title">ТТ</div>
						<div>
							<input type="text" ref="tradePoint" list="ttdistribution" placeholder="Укажите ТТ">
								<datalist id="ttdistribution">
									<option v-for="tp in tradepointsList" :value="tp.name"></option>
								</datalist>
							</select>
						</div>
					</div>
					<div class="Fblock">
						<div class="title">Аудитор</div>
						<div>
							<input type="text" ref="auditor" list="auditordistribution" placeholder="Выберите аудитора">
							<datalist id="auditordistribution">
								<option v-for="auditor in auditors" :value="auditor.name"></option>
							</datalist>
						</div>
					</div>
					<div class="Fblock">
						<div class="title">Сегменты</div>
						<div>
							<select multiple size="5" ref="segments">
								<option v-for="seg in segmentsList" :value="seg.code" selected>{{ seg.name }}</option>
							</select>
						</div>
					</div>
					<div class="Fblock">
						<div class="title">&nbsp;</div>
						<div>
							<input type="button" class="submit" value="Сохранить" title="[F2]" :disabled="pendingDistribution" @click="saveDistribution">
						</div>
					</div>
				</form>
				<div class="distroList" v-for="(distr, idx) in distributions">
					<div class="Fblock">
						<div class="title" v-if="!idx">ТТ</div>
						<div class="text">{{ distr.shop.address }}</div>
					</div>
					<div class="Fblock">
						<div class="title" v-if="!idx">Аудитор</div>
						<div class="text">{{ distr.auditor.first_name + ' ' + distr.auditor.last_name }}</div>
					</div>
					<div class="Fblock">
						<div class="title" v-if="!idx">Сегменты</div>
						<div class="text">{{ (segmentsList.length == distr.segments.length) ? 'Все сегменты' : distr.segments.map(S => S.name).join(', ') }}</div>
					</div>
					<div class="Fblock">
						<div class="title" v-if="!idx">&nbsp;</div>
						<img src="@/assets/img/del_cross.svg" alt="Удалить" @click="deleteDistribution(distr.id)">
					</div>
				</div>
			</div>
		</div>
	</div>
</template>

<script>
import filterBlock from '@/components/filterBlock'
import pager from '@/components/pager'
import Datepicker from 'vuejs-datepicker'
import {ru} from 'vuejs-datepicker/dist/locale'
export default {
	data() {
		return {
			ru: ru,
			type: 'waves',
			waves: [],
			waveInfo: null,         // Объект с информацией об отображаемой волне
			waveInfoLoading: false, // Загрузка waveInfo
			disableAddForm: false,  // При редактировании блоки добавления должны быть не активны
			totalWavesCount: 0,
			totalWavesSTR: '…',
			page: 1,

			auditors: [],
			filters: null,          // Фильтры полного списка
			filtersDetails: null,   // Фильтры детального вида волны
			clientsList: [],
			tradepointsList: [],
			segmentsList: [],

			detailsInfo: null,      // id волны, которую нужно показать подробно и распределить
			distributions: [],
			distributionsNets: [],  // Для фильтра сетей
			pendingDistribution: false,  // Защита от дублирующего распределения волны
			pendingAddWave: false,  // Защита от дублирующего создания волны

			showAddWaveForm: false,
			addWaveForm: {          // Форма добавления и редактирования. При редактировании не активна
				dateFrom: '',
				dateTo:   '',
				client:   -1
			},

			loadFileTT: 'Загрузить ТТ',
			loadFileSegments: 'Загрузить сегменты',
			loadTabs: {            // Статусы для работы с табами загрузки файлов
				active: {
					tabTT: true,
					tabSegments: false
				},
				loading: {         // Загрузка файлов на сервер
					tt: false,
					segments: false
				}
			}
		}
	},

	created() {
		this.clearFilters('init')
		this.clearFiltersDetails('init')
		this.$store.dispatch('setLastPage', this.type)
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))

		if (!this.uRoles.length || !this.linksToDraw[this.type]) {
			location.hash = '#/splash'
			return
		}

		this.refreshList()

		// Подгрузка списка клиентов для фильтра
		window.worker.postMessage({
			type: 'clients',
			token: this.token
		})

		// Подгрузка списка аудиторов для селекта в блоке распределения волны
		if (!this.isAdmin)
			window.worker.postMessage({
				type: 'auditorsFilter',
				token: this.token
			})

		window.addEventListener('keyup',  this.keyHandler, false)
		window.worker.addEventListener('message', this.workerHandler, false)
	},

	beforeDestroy() {
		window.removeEventListener('keyup', this.keyHandler)
		window.worker.removeEventListener('message', this.workerHandler)
	},

	methods: {
		keyHandler(E) {
			let M

			if (E.code == 'Backslash' && E.ctrlKey && E.altKey && !E.shiftKey)
				this.refreshList()

			else if (E.code == 'Escape') {
				if (this.showAddWaveForm)
					this.exitAddWaveForm()
				else if (this.detailsInfo !== null)
					this.exitDetails()
			}

			else if (E.code == 'F2' && !E.ctrlKey && !E.altKey && !E.shfitKey) {
				if (this.detailsInfo !== null && !this.isAdmin)
					this.saveDistribution()
				else if (this.showAddWaveForm)
					this.addWave()
			}

			else if (E.code == 'KeyC' && E.altKey && !E.ctrlKey && !E.shiftKey) {
				if (this.detailsInfo === null && this.isAdmin)
					this.displayAddWaveForm()
			}

			// Листалка страниц на ctrl+стрелки
			else if (E.ctrlKey && (E.code == 'ArrowLeft' || E.code == 'Numpad4') && !E.altKey && !E.shiftKey)
				this.goToPage(Math.max(0, this.page - 1))
			else if (E.ctrlKey && (E.code == 'ArrowRight' || E.code == 'Numpad6') && !E.altKey && !E.shiftKey)
				++this.page

			else if (E.ctrlKey && E.shiftKey && !E.altKey && (M = E.code.match(/^(?:Numpad|Digit)([0-9])$/))) {
				if (M[1] > 0)
					this.page = parseInt(M[1])
			}
		},

		workerHandler(ev) {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				case 'waves':
					let totalWaves = 0
					if (ev.data.waves) {
						this.waves = ev.data.waves
						totalWaves = Number(ev.data.count)
					}
					this.totalWavesCount = totalWaves
					this.totalWavesSTR = this.totalWavesCount.toString().replace(/(\d)(?=(\d{3})+\b)/g,'$1 ')
					break

				// Клиенты для фильтра
				case 'clients':
					this.clientsList = ev.data.clients
					break

				// Аудиторы для селекта при распределении (наставнику)
				case 'auditorsFilter':
					if ('auditors' in ev.data)
						this.auditors = ev.data.auditors.sort((A, B) => A.name > B.name)
					break

				// Детализация одной волны
				case 'waveInfo':
					this.waveInfo = ev.data.waveInfo
					this.waveInfoLoading = false
					this.segmentsList = ev.data.waveInfo.segments
					this.tradepointsList = ev.data.waveInfo.shops.map(E => {
						return {
							id: E.eid,
							name: E.address
						}
					}).sort((A, B) => A.name > B.name)

					this.addWaveForm.dateFrom = this.waveInfo.begin
					this.addWaveForm.dateTo = this.waveInfo.end
					this.addWaveForm.client = this.waveInfo.customer.id
					this.addWaveForm.name = this.waveInfo.name

					if ('nets' in ev.data)
						this.distributionsNets = ev.data.nets
					break

				// Распределения волны
				case 'waveDistributions':
					if ('distributions' in ev.data)
						this.distributions = ev.data.distributions
					break

				// Распределение создано
				case 'distributionCreated':
					this.pendingDistribution = false
					this.$refs.addForm.reset()
					this.refreshDistributions()
					break

				// Распределение удалено
				case 'distributionDeleted':
					this.refreshDistributions()
					break

				// Пришёл обновлённый статус одной волны
				case 'checkWaveStatus':
					const waveIndex = this.waves.reduce((found, W, index) => (W.id == ev.data.id ? index : found), -1)
					if (waveIndex >= 0) {
						this.waves[waveIndex].distribution_status = ev.data.status
						this.waves[waveIndex].begin = ev.data.dateFrom
						this.waves[waveIndex].end = ev.data.dateTo
						this.waves[waveIndex].customer = ev.data.client
						this.waves[waveIndex].name = ev.data.name
					}
					break

				// Волна добавлена
				case 'waveAdded':
					this.pendingAddWave = false
					if (this.isEditing)
						ev.data.wave = this.waveInfo.id
					this.showDistributionForm(ev.data.wave)
					break

				// Файл торговых точек загружен на сервер
				case 'ttLoaded':
					this.loadTabs.loading.tt = false
					if (this.detailsInfo !== null && ev.data.wave == this.detailsInfo) {

						this.detailsInfo = null
						this.$nextTick(() => { this.detailsInfo = ev.data.wave })
					}
					break

				// Файл сегментов загружен на сервер
				case 'segmentsLoaded':
					this.loadTabs.loading.segments = false
					if (this.detailsInfo !== null && ev.data.wave == this.detailsInfo) {
						this.detailsInfo = null
						this.$nextTick(() => { this.detailsInfo = ev.data.wave })
					}
					break

				case 'badImport':
					if (ev.data.tab == 'tt')
						this.loadTabs.loading.tt = false
					else
						this.loadTabs.loading.segments = false

					alert('Не удалось загрузить файл ' + (ev.data.tab == 'tt' ? 'торговых точек' : 'сегментов'))
					break
			}
		},

		refreshList(resetPage) {
			if (this.token) {
				this.waves = []
				this.totalWavesCount = 0
				this.totalWavesSTR = '…'

				if (resetPage !== undefined && this.page !== 1)
					this.page = 1
				else
					window.worker.postMessage({
						type: this.type,
						page: this.page,
						pageSize: this.pageSize,
						token: this.token,
						filters: this.filters
					})
			}
		},

		// Обновление списка распределений у волны
		refreshDistributions() {
			if (this.detailsInfo === null) return

			this.distributions = []
			window.worker.postMessage({
				type: 'waveDistributions',
				token: this.token,
				wave: this.detailsInfo,
				filters: this.filtersDetails
			})
		},

		clearFilters(init) {
			this.filters = {
				dateFrom: '',
				dateTo:   '',
				client:   -1,
				wave:     '',
				status:   -1
			}

			if (init === undefined)
				this.refreshList('resetPage')
		},

		setFilter(data) {
			this.filters = Object.assign(this.filters, data)

			this.refreshList('resetPage')
		},

		clearFiltersDetails(init) {
			this.filtersDetails = {
				auditor:    -1,
				tradePoint: -1,
				segment:    -1
			}

			if (init === undefined)
				this.refreshDistributions()
		},

		setFilterDetails(data) {
			this.filtersDetails = Object.assign(this.filtersDetails, data)

			this.refreshDistributions()
		},

		gotoPage(page) {
			this.page = page
		},

		// Показ формы распределения или редактирования волны
		showDistributionForm(id) {
			if (this.isAdmin) {
				let wave = this.waves.filter(W => W.id == id)[0]
				this.showAddWaveForm = true
				this.showAddWaveForm = true
				//FLAG Эту переменную нужно выключить, потому что нужно редактирование дат волны
				//this.disableAddForm = true
				if (wave) {
					this.addWaveForm.dateFrom = wave.begin
					this.addWaveForm.dateTo = wave.end
					this.addWaveForm.client = wave.customer.id
					this.addWaveForm.name = wave.name
				}
			}

			this.waveInfo = null
			this.detailsInfo = null
			this.$nextTick(() => { this.detailsInfo = id })
		},

		// Создание распределения волны
		saveDistribution() {
			if (this.pendingDistribution) return
			const segments = Array.from(this.$refs.segments.selectedOptions).map(SE => parseInt(SE.value))

			const TPitem = this.tradepointsList.filter(T => T.name == this.$refs.tradePoint.value)
			if (!TPitem.length) return
			const TP = TPitem[0].id

			const auditoritem = this.auditors.filter(A => A.name == this.$refs.auditor.value)
			if (!auditoritem.length) return
			const auditor = auditoritem[0].id

			if (TP == -1 || auditor == -1 || !segments.length) {
				if (!segments.length) this.$refs.segments.focus()
				if (auditor == -1) this.$refs.auditor.focus()
				if (TP == -1) this.$refs.tradePoint.focus()
				return
			}

			this.pendingDistribution = true

			window.worker.postMessage({
				type: 'createDistribution',
				token: this.token,
				distribution: {
					monitoring_wave: this.detailsInfo,
					auditor: auditor,
					shop: TP,
					segments: segments
				}
			})
		},

		// Удаление распределения
		deleteDistribution(id) {
			if (!confirm('Действительно удалить?')) return

			window.worker.postMessage({
				type: 'deleteDistribution',
				token: this.token,
				id: id
			})
		},

		// Выход из распределения
		exitDetails() {
			window.worker.postMessage({
				type: 'checkWaveStatus',
				token: this.token,
				id: this.detailsInfo
			})
			this.detailsInfo = null
		},

		// Выход из формы добавления
		exitAddWaveForm() {
			if (this.isEditing)
				window.worker.postMessage({
					type: 'checkWaveStatus',
					token: this.token,
					id: this.waveInfo.id
				})

			this.disableAddForm = false
			this.showAddWaveForm = false
			this.detailsInfo = null
			this.loadFileTT = 'Загрузить ТТ'
			this.loadFileSegments = 'Загрузить сегменты'
		},

		// Отображение формы создания волны
		displayAddWaveForm() {
			if (!this.isAdmin) return
			this.addWaveForm.dateFrom = ''
			this.addWaveForm.dateTo = ''
			this.addWaveForm.client = -1
			this.addWaveForm.name = ''
			this.showAddWaveForm = true
			this.disableAddForm = false
		},

		// Создание волны
		addWave() {
			if (this.addWaveForm.name == '' || this.addWaveForm.dateFrom == '' || this.addWaveForm.dateTo == '' || this.addWaveForm.client == -1)
				return
			this.pendingAddWave = true

			window.worker.postMessage({
				type: 'addWave',
				token: this.token,
				data: this.addWaveForm,
				id: this.isEditing ? this.waveInfo.id : 0,
				method: this.isEditing ? 'edit' : 'add'
			})
		},

		// Загрузка торговых точек
		loadTradePoints(E) {
			this.loadTabs.loading.tt = true
			const file = new FileReader()
			file.onload = () => {
				window.worker.postMessage({
					type: 'loadFileTT',
					token: this.token,
					wave: this.detailsInfo,
					file: file.result
				})
			}
			file.readAsArrayBuffer(E.target.files[0])
		},

		// Загрузка сегментов
		loadSegments(E) {
			this.loadTabs.loading.segments = true
			const file = new FileReader()
			file.onload = () => {
				window.worker.postMessage({
					type: 'loadFileSegments',
					token: this.token,
					wave: this.detailsInfo,
					file: file.result
				})
			}
			file.readAsArrayBuffer(E.target.files[0])
		},

		// Сработал выбор файла ТТ в инпуте
		ttSelected(E) {
			this.loadFileTT = E.target.files[0].name
			this.loadTradePoints(E)
		},

		// Сработал выбор файла сегментов в инпуте
		segmentsSelected(E) {
			this.loadFileSegments = E.target.files[0].name
			this.loadSegments(E)
		},

		// Смена видимого таба
		changeLoadTab(tab) {
			this.loadTabs.active.tabTT = tab == 'tt'
			this.loadTabs.active.tabSegments = tab == 'segments'
		}
	},

	watch: {
		token(newToken) {
			if (newToken !== null && this.uRoles.length && this.refreshList)
				this.refreshList()
		},

		page() {
			this.refreshList()
		},

		// Выбор волны для показа деталей
		detailsInfo(waveId) {
			if (waveId !== null) {
				window.worker.postMessage({
					type: 'waveInfo',
					token: this.token,
					id: waveId
				})
				this.waveInfoLoading = true

				this.loadTabs.loading.tt = false
				this.loadTabs.loading.segments = false
				this.clearFiltersDetails()
			}
			else
				this.waveInfo = null
		}
	},

	computed: {
		filterFields() {
			return [
				{
					type: 'date',
					name: 'dateFrom',
					placeholder: 'Дата с',
					row: 1
				},
				{
					type: 'date',
					name: 'dateTo',
					placeholder: 'Дата до',
					row: 1
				},
				{
					type: 'select',
					name: 'client',
					placeholder: 'Клиент',
					row: 1,
					options: this.clientsList,
					placeholderDisabled: true
				},
				{
					type: 'reset',
					value: 'Очистить фильтры',
					width: 2,
					row: 1
				},
				{
					type: 'input',
					name: 'wave',
					placeholder: 'Название волны',
					row: 2,
					width: 2
				},
				{
					type: 'select',
					name: 'status',
					placeholder: 'Статус',
					row: 2,
					options: [{id: 'distributed', name: 'распределён'}, {id: 'distributing', name: 'не распределён'}],
					placeholderDisabled: true
				},
				{
					type: 'submit',
					value: 'Применить',
					width: 2,
					row: 2
				}
			]
		},

		filterFieldsDetails() {
			return [
				{
					type: 'select',
					name: 'auditor',
					placeholder: 'Аудитор',
					row: 1,
					options: this.auditors
				},
				{
					type: 'select',
					name: 'tradePoint',
					placeholder: 'ТТ',
					row: 1,
					options: this.tradepointsList
				},
				{
					type: 'select',
					name: 'segment',
					placeholder: 'Сегмент',
					row: 1,
					options: this.segmentsList
				},
				{
					type: 'input',
					name: 'town',
					placeholder: 'Город',
					row: 1,
					width: 2
				},
				{
					type: 'select',
					name: 'net',
					placeholder: 'Торговая сеть',
					row: 1,
					width: 2,
					options: this.distributionsNets
				},
				{
					type: 'reset',
					value: 'Очистить фильтры',
					width: 2,
					row: 1
				},
				{
					type: 'submit',
					value: 'Применить',
					width: 2,
					row: 1
				}
			]
		},

		// Окончание для 'волн'
		wavesWordEnd() {
			const C10 = this.totalWavesCount % 10
			const C100 = this.totalWavesCount % 100
			let R

			if (C100 > 10 && C100 < 20 || C10 > 4 || C10 == 0) R = ''
			else if (C10 == 1) R = 'а'
			else R = 'ы'

			return R
		},

		pagesCount() {
			return Math.ceil(this.totalWavesCount / this.pageSize)
		},

		isAdmin() {
			return this.hasOnlyRole('admin')
		},

		isEditing() {
			return this.waveInfo && this.waveInfo.id
		}
	},

	components: {pager, filterBlock, Datepicker}
}
</script>

