<template>
	<!-- ctrl+alt+"\" обновляет записи -->
	<div>
		<div class="body" v-show="!showDetailView">
			<div class="header">Записи</div>
			<tabLine :tabs="tabs" :initialTab="filters.tab" @change="changeTab" v-if="!hasOnlyRole('auditor')"/>
			<filterBlock :filterFields="filterFields" :page="type" v-if="!hasOnlyRole('auditor')" @clientChanged="chClient" @waveChanged="chWave" @networkChanged="chNetwork" @reset="clearFilters" @submit="setFilter" @currentFilter="setFiltersValues"/>
			<div class="counter-pager-submit">
				<label class="checkAll" v-if="['toclient', 'deleted'].indexOf(filters.tab) == -1">
					<input type="checkbox" @change="checkAll($event), calcCheckedCount()" :key="'p' + page">
					<span>Выбрать все</span>
				</label>
				<span class="recordsCount">{{ totalRecordsSTR }} запис{{ recWordEnd(totalRecordsCount) }}</span>
				<span class="selected" v-if="checkedCount">Выбран{{ checkedWordEnd }} {{ checkedCount }} запис{{ recWordEnd(checkedCount) }}</span>
				<pager v-if="totalRecordsCount > pageSize" :currentPage="page" :pagesCount="pagesCount" @changePage="gotoPage"/>
				<button class="submit redButton" v-if="checkedCount && filters.tab != 'toclient'" @click="saveRecords" title="[F2]">Отправить данные</button>
				<button class="submit redButton" v-if="filters.tab == 'toclient'" :disabled="pendingExport || Object.getOwnPropertyNames(filtersValues).length == 1 || filtersValues.wave == -1" @click="requestExport">Выгрузка в Excel</button>
				<button class="submit redButton freeWidth" v-if="filters.tab == 'moderation'" :disabled="moderationSendPending || filtersValues.wave == undefined || filtersValues.wave == -1" :title="(filtersValues.wave == undefined || filtersValues.wave == -1) ? 'Нужно выбрать волну' : '[Ctrl+F9]'" @click="AllToSent">Переместить все в отправленные</button>
			</div>
			<div class="exportLinks" v-if="exportLinks.length || pendingExport">
				<div v-if="exportLinks.length">Экспортированные файлы</div>
				<div class="links" v-if="exportLinks.length">
					<a v-for="link in exportLinks" :href="linksPrefix + link">{{ link.replace(/^.+\//, '') }}</a>
				</div>
				<progress v-if="pendingExport"></progress>
				<button v-if="exportLinks.length" @click="exportLinks = []">Скрыть ссылки</button>
			</div>
			<itemsTable
				:list="records"
				:type="type"
				:subType="filters.tab"
				:visibleFields="visibleFields"
				:headerFilters="headerFilters"
				:segmentsList="segmentsList"
				:tradePointsList="tradePointsList"
				:netsList="networksList"
				@showDetails="showDetails"
				@moreButtonPressed="showDetails"
				@imgClick="showDetails"
				@check="calcCheckedCount"
				@headerFilterChanged="setHeaderFilters"
				@applyFilters="refreshList"
				@sortingChange="sortingChange"
				/>
			<pager v-if="totalRecordsCount > pageSize" :currentPage="page" :pagesCount="pagesCount" @changePage="gotoPage"/>
		</div>

		<div class="body detail" v-show="showDetailView" :key="recordDetails.id ? recordDetails.id : 0">
			<div class="header">
				<div class="backButton" @click="hideDetails" title="[Escape]"><img src="@/assets/img/back.svg">назад</div>
				Подробная информация
			</div>
			<div class="buttons">
				<div class="arrows">
					<div :class="{arrow: true, left: true, disabled: !prevRecord}" @click="switchToRecord('prev')" title="Предыдущая запись [Ctrl + ←]"></div>
					<div :class="{arrow: true, right: true, disabled: !nextRecord}" @click="switchToRecord('next')" title="Следующая запись [Ctrl + →]"></div>
				</div>
				<div class="redButtons" v-if="filters.tab != 'deleted'">
					<button class="redButton transparent" title="[Ctrl + Del]" @click="deleteRecord()"><img src="@/assets/img/trash.svg" alt="">Удалить запись</button>
					<div class="priceline_top" v-if="filters.tab == 'moderation'">
						<bigInput title="Цена обычная"  :hideTitle="filters.tab != 'moderation'" v-model="recordDetails.general_price" :blocked="['toclient', 'deleted'].indexOf(filters.tab) != -1" @input="recordDetails.checked = true, calcCheckedCount(), checkChangedPrice()" @keyup.enter="switchToInput('card')" name="ordinary"/>
						<bigInput title="Цена по карте" :hideTitle="filters.tab != 'moderation'" v-model="recordDetails.card_price" :blocked="['toclient', 'deleted'].indexOf(filters.tab) != -1" @input="recordDetails.checked = true, calcCheckedCount(), checkChangedPrice()" @keyup.enter="switchToInput('sale')" name="card"/>
						<bigInput title="Цена по акции" :hideTitle="filters.tab != 'moderation'" v-model="recordDetails.sale_price" :blocked="['toclient', 'deleted'].indexOf(filters.tab) != -1" @input="recordDetails.checked = true, calcCheckedCount(), checkChangedPrice()" name="sale"/>
					</div>
					<button class="redButton" title="[F2]" v-if="filters.tab != 'toclient'" @click="saveAction" :disabled="detailSaveDisabled">Отправить данные</button>
				</div>
			</div>

			<div v-if="filters.tab != 'moderation'">
				<table class="item">
					<tr>
						<th v-if="!hasOnlyRole('auditor')">Аудитор</th>
						<th>Название товара</th>
						<th>Бренд</th>
						<th>Сеть</th>
