						<th v-if="filters.tab == 'moderation'">Разница</th>
						<th v-if="filters.tab == 'moderation'">Акция</th>
						<th v-if="filters.tab == 'moderation'">Ашан</th>
						<th v-if="filters.tab == 'moderation'">Пред</th>
						<th class="wider"></th>
					</tr>
					<tr v-if="recordDetails.auditor">
						<td class="auditor" v-if="!hasOnlyRole('auditor')">{{ getAuditorName(recordDetails.auditor) }}</td>
						<td class="itemName" :title="recordDetails.sku && recordDetails.sku.segment && recordDetails.sku.segment.name">{{ recordDetails.sku && recordDetails.sku.name }}</td>
						<td class="brand">{{ recordDetails.sku && recordDetails.sku.brand }}</td>
						<td class="net">{{ recordDetails.shop.retail_network.name }}</td>
						<td class="barcode">{{ recordDetails.sku.barcode }}</td>
						<td class="address">{{ recordDetails.shop.address }}</td>
						<td class="date">{{ convertDate(recordDetails.import_time) }}</td>
						<td class="wave">{{ recordDetails.monitoring_waves[0].id }}</td>
						<td class="client">{{ recordDetails.monitoring_waves[0].customer.name }}</td>
						<td class="percent" v-if="filters.tab == 'moderation'">{{ drawPercent(recordDetails.card_current_diff_percent) }}</td>
						<td class="percent" v-if="filters.tab == 'moderation'">{{ drawPercent(recordDetails.sale_current_diff_percent) }}</td>
						<td class="percent" v-if="filters.tab == 'moderation'" v-html="calcAuchanPercent(recordDetails)"></td>
						<td class="percent" v-if="filters.tab == 'moderation'">{{ drawPercent(recordDetails.general_previous_diff_percent) }}</td>
						<td class="wider"></td>
					</tr>
				</table>
			</div>
			<div v-else>
				<table class="item">
					<tr>
						<th v-if="!hasOnlyRole('auditor')">Аудитор</th>
						<th>Адрес</th>
						<th>Сеть</th>
						<th>Дата</th>
						<th>Волна</th>
						<th>Клиент</th>
						<th class="wider"></th>
					</tr>
					<tr v-if="recordDetails.auditor">
						<td class="auditor" v-if="!hasOnlyRole('auditor')">{{ getAuditorName(recordDetails.auditor) }}</td>
						<td class="address">{{ recordDetails.shop.address }}</td>
						<td class="net">{{ recordDetails.shop.retail_network.name }}</td>
						<td class="date">{{ convertDate(recordDetails.import_time) }}</td>
						<td class="wave">{{ recordDetails.monitoring_waves[0].id }}</td>
						<td class="client">{{ recordDetails.monitoring_waves[0].customer.name }}</td>
						<td class="wider"></td>
					</tr>
				</table>
				<table class="item">
					<tr>
						<th>Штрихкод</th>
						<th>Бренд</th>
						<th>Производитель</th>
						<th>Сегмент</th>
						<th>Название товара</th>
						<th class="wider"></th>
					</tr>
					<tr v-if="recordDetails.auditor && recordDetails.sku">
						<td class="barcode"><customInput class="bigfont" v-model="recordDetails.sku.barcode" maxlength="13" textField="true" @change="loadBarcode" @input="clearItem" @keydown.enter="loadBarcode" @keydown.esc="restoreItem" title="[Enter] — загрузить SKU по штрихкоду, [Esc] — вернуть исходные данные" ref="barcode"/></td>
						<td class="brand"><customInput class="bigfont" v-model="recordDetails.sku.brand" :readonly="recordDetails.sku.barcode != recordDetails.sku.srcBarcode" textField="true" @change="loadProducersSuggestions(recordDetails.sku.brand)"/></td>
						<td class="producer">
							<customInput class="bigfont" v-model="recordDetails.sku.producer" :readonly="recordDetails.sku.barcode != recordDetails.sku.srcBarcode" textField="true" :list="'pr' + recordDetails.id"/>
							<datalist v-if="producersSuggestions[recordDetails.id] && producersSuggestions[recordDetails.id].length" :id="'pr' + recordDetails.id">
								<option v-for="sug of producersSuggestions[recordDetails.id]" :value="sug"/>
							</datalist>
						</td>
						<td class="segment">
							<select v-model="recordDetails.sku.segment.code" :disabled="segmentsList === undefined || !segmentsList.length || recordDetails.sku.barcode != recordDetails.sku.srcBarcode">
								<option v-for="seg in segmentsList" :value="seg.code">{{ seg.name }}</option>
							</select>
						</td>
						<td class="itemName"><customInput class="bigfont" v-model="recordDetails.sku.name" :readonly="recordDetails.sku.barcode != recordDetails.sku.srcBarcode" textField="true"/></td>
						<td class="wider"></td>
					</tr>
				</table>
				<!-- <table class="item">
					<tr>
						<th title="Разница обычной цены и цены по карте">Разница</th>
						<th title="Разница обычной цены и цены по акции">Акция</th>
						<th title="Разница обычной и средней цен">Ашан</th>
						<th title="Разница текущей и предыдущей обычных цен">Пред</th>
						<th title="Разница текущей и предыдущей цен по карте">Пред. карта</th>
						<th title="Разница текущей и предыдущей цен по акции">Пред. акция</th>
						<th class="wider"></th>
					</tr>
					<tr>
						<td class="percent" title="Разница обычной цены и цены по карте">{{ drawPercent(recordDetails.card_current_diff_percent) }}</td>
						<td class="percent" title="Разница обычной цены и цены по акции">{{ drawPercent(recordDetails.sale_current_diff_percent) }}</td>
						<td class="percent" title="Разница обычной и средней цен" v-html="calcAuchanPercent(recordDetails)"></td>
						<td class="percent" title="Разница текущей и предыдущей обычных цен">{{ drawPercent(recordDetails.general_previous_diff_percent) }}</td>
						<td class="percent" title="Разница текущей и предыдущей обычных цен">{{ drawPercent(recordDetails.card_previous_diff_percent) }}</td>
						<td class="percent" title="Разница текущей и предыдущей цен по акции">{{ drawPercent(recordDetails.sale_previous_diff_percent) }}</td>
						<td class="wider"></td>
					</tr>
				</table> -->
			</div>
			<div class="prices" v-if="recordDetails.auditor && filters.tab != 'moderation'">
				<div class="price new">
					<div class="priceline">
						<bigInput title="Цена обычная"  old="true" v-model="recordDetails.previous_general_price"/>
						<bigInput title="Цена по карте" old="true" v-model="recordDetails.previous_card_price"/>
						<bigInput title="Цена по акции" old="true" v-model="recordDetails.previous_sale_price"/>
					</div>
					<div class="priceline">
						<bigInput title="Цена обычная"  :hideTitle="filters.tab != 'moderation'" v-model="recordDetails.general_price" :blocked="['toclient', 'deleted'].indexOf(filters.tab) != -1" @input="recordDetails.checked = true, calcCheckedCount(), checkChangedPrice()" @keyup.enter="switchToInput('card')" name="ordinary"/>
						<bigInput title="Цена по карте" :hideTitle="filters.tab != 'moderation'" v-model="recordDetails.card_price" :blocked="['toclient', 'deleted'].indexOf(filters.tab) != -1" @input="recordDetails.checked = true, calcCheckedCount(), checkChangedPrice()" @keyup.enter="switchToInput('sale')" name="card"/>
						<bigInput title="Цена по акции" :hideTitle="filters.tab != 'moderation'" v-model="recordDetails.sale_price" :blocked="['toclient', 'deleted'].indexOf(filters.tab) != -1" @input="recordDetails.checked = true, calcCheckedCount(), checkChangedPrice()" name="sale"/>
					</div>
				</div>
				<div class="price">
					<button :class="{redButton: true, blueButton: true, filled: recordDetails.price_not_changed, totop: filters.tab == 'moderation'}" title="[F9]" v-if="['priceless'].indexOf(filters.tab) != -1" @click="priceNotChanged">Цена не изменилась</button>
				</div>
			</div>
			<div class="images" v-if="recordDetails.auditor">
				<rotatingImg :src="recordDetails.barcode_photo.photo" @click="showImage(recordDetails.barcode_photo.photo)"/>
				<rotatingImg :src="recordDetails.price_photo.photo" @click="showImage(recordDetails.price_photo.photo)"/>
				<rotatingImg v-for="photo in recordDetails.other_photos" :src="photo.photo" @click="showImage(photo.photo)"/>
			</div>

			<div class="overlay" v-if="showFullImage" @click="showFullImage = false">
				<img :src="fullImageSrc" alt="" @click.stop="">
			</div>
		</div>

		<div class="overlay lock" v-if="pendingExport"></div>
	</div>
</template>

<script>
import itemsTable from '@/components/itemsTable'
import pager from '@/components/pager'
import tabLine from '@/components/tabLine'
import filterBlock from '@/components/filterBlock'
import customInput from '@/components/input'
import bigInput from '@/components/bigInput'
import rotatingImg from '@/components/rotatingImg'
export default {
	components: {itemsTable, pager, tabLine, filterBlock, bigInput, rotatingImg, customInput},

	data() {
		return {
			type: 'records',
			records: [],
			checkedCount: 0,    // Количество отмеченных
			totalRecordsSTR: '…',
			totalRecordsCount: 0,
			page: 1,

			// Введённые пользователем фильтры
			filters: null,
			// Видимые в таблице поля
			visibleFields: null,
			showFilesFilter: false,

			// Поля для фильтра
			clientsList:     [],
			networksList:    [],
			tradePointsRaw:  [],
			filterFilesList: [],    // Список файлов для фильтра по файлу в экспорте
			wavesList:       [],
			segmentsList:    [],
			showAuditorsFilter: true,
			showPricechangeFilter: true,
			selectedNetwork: null,
			headerFilters: {       // Фильтры в заголовке таблицы (в модерации)
				perc_card_current:  '',
				perc_sale_current:  '',
				perc_average:       '',
				perc_general_previous: '',
				perc_card_previous: '',
				perc_sale_previous: '',
				auditor:            '',
				segment:            '',
				tradePoint:         ''
			},

			nextRecord: null,
			prevRecord: null,

			showDetailView: false,
			needRefresh: false,     // Необходимость перезагрузки полного списка при выходе из подробного просмотра
			scrollPos: 0,           // Позиция скрола на момент открытия подробного просмотра
			recordDetails: {},
			showFullImage: false,   // Просмотр крупных картинок
			fullImageSrc: '',

			pendingExport: false,   // Идёт процесс запроса экспорта
			exportLinks: [],
			filtersValues: {},      // Текущее состояние фильтров, без применения

			nextRecordPending: false,
			immediatelySwitchToNext: false,
			producersSuggestions: {},
			moderationSendPending: false,

			sorting: ''             // Сортировка записей в таблице
		}
	},

	created() {
		this.clearFilters('init')
		this.setInVisibleFields()    // Без параметров — все поля видимы
		this.$store.dispatch('setLastPage', this.type)
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))

		if (!this.uRoles.length || !this.linksToDraw[this.type]) {
			location.hash = '#/splash'
			return
		}

		this.refreshList()
		this.setVFieldsToUser()

		// Подгрузка списка клиентов для фильтра
		if (!this.hasOnlyRole('auditor')) {
			window.worker.postMessage({
				type: 'clients',
				token: this.token
			})

			window.worker.postMessage({
				type: 'auditors',
				token: this.token
			})
		}

		// Загрузка списка сегментов для фильтра
		window.worker.postMessage({
			type: 'segments',
			token: this.token
		})
		// Загрузка имён файлов для фильтра
		if (this.hasOnlyRole('coordinator'))
			window.worker.postMessage({
				type: 'filterFilesList',
				token: this.token
			})

		window.addEventListener('keyup',  this.keyHandler, false)
		window.worker.addEventListener('message', this.workerHandler, false)
		this.exportInterval = setInterval(this.checkExportLinks, 5000)
	},

	beforeDestroy() {
		if (this.exportInterval) clearInterval(this.exportInterval)
		window.removeEventListener('keyup', this.keyHandler)
		window.worker.removeEventListener('message', this.workerHandler)
	},

	methods: {
		keyHandler(E) {
			let M
			if (this.pendingExport) return

			if (E.code == 'Escape' && !E.ctrlKey && !E.altKey && !E.shiftKey && this.showDetailView) {
				if (this.$refs.barcode && E.target == this.$refs.barcode.$el)
					return

				if (this.showFullImage)
					this.showFullImage = false
				else
					this.hideDetails()
			}

			else if (E.code == 'Backslash' && E.ctrlKey && E.altKey &&  !E.shiftKey) {
				E.preventDefault()
				this.refreshList()
			}

			// Сохранить
			else if (E.code == 'F2' && !E.ctrlKey && !E.altKey && !E.shiftKey) {
				E.preventDefault()
				if (this.filters.tab != 'deleted')
					this.saveAction()
			}

			// Цена не изменилась
			else if (E.code == 'F9' && !E.shiftKey && !E.altKey && !E.ctrlKey && ['priceless'].indexOf(this.filters.tab) != -1) {
				E.preventDefault()
				this.priceNotChanged()
			}

			// Ctrl+Del — удаление записи
			else if ((E.code == 'Delete' || E.code == 'NumpadDecimal') && E.ctrlKey && !E.altKey && !E.shiftKey) {
				E.preventDefault()
				if (this.filters.tab != 'deleted')
					this.deleteRecord()
			}

			// Листалка страниц на ctrl+стрелки
			else if (E.ctrlKey && (E.code == 'ArrowLeft' || E.code == 'Numpad4') && !E.altKey && !E.shiftKey) {
				if (!this.showDetailView)
					this.gotoPage(Math.max(0, this.page - 1))
				else
					this.switchToRecord('prev')
			}
			else if (E.ctrlKey && (E.code == 'ArrowRight' || E.code == 'Numpad6') && !E.altKey && !E.shiftKey) {
				if (!this.showDetailView)
					++this.page
				else
					this.switchToRecord('next')
			}

			else if (!this.showDetailView && E.ctrlKey && E.shiftKey && !E.altKey && (M = E.code.match(/^(?:Numpad|Digit)([0-9])$/))) {
				if (M[1] > 0)
					this.page = parseInt(M[1])
			}

			// Перенести записи из модерации в отправленные
			else if (E.code == 'F9' && !this.showDetailView && E.ctrlKey && !E.altKey && !E.shiftKey) {
				E.preventDefault()
				if (this.filtersValues.wave != -1)
					this.AllToSent()
			}
		},

		workerHandler(ev) {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				// Записи
				case 'records':
					let totalRecords = 0
					if (ev.data.records) {
						this.records = ev.data.records
						totalRecords = Number(ev.data.count)
					}
					this.totalRecordsCount = totalRecords
					this.totalRecordsSTR = this.totalRecordsCount.toString().replace(/(\d)(?=(\d{3})+\b)/g,'$1 ')
					break

				// Клиенты для фильтра
				case 'clients':
					this.clientsList = ev.data.clients
					break

				// Список волн для фильтра
				case 'wavesFilter':
					this.wavesList = ev.data.waves
					break

				// Список торговых сетей для фильтра
				case 'networks':
					this.networksList = ev.data.networks
					break

				// Список торговых точек для фильтра
				case 'tradePoints':
					const list = ev.data.tradePoints.map(W => {
						const wave = W
						wave.name  = W.address
						wave.id = W.eid
						return wave
					})					
					list.sort((W1, W2) => W1.address > W2.address ? 1 : -1)
					this.tradePointsRaw = list 
					break

				case 'recordsSaved':
					if (ev.data.keepDetails) {
						this.needRefresh = true
						this.scrollPos = 0

						if (this.nextRecord !== null)
							this.switchToRecord('next')
						else {
							// Если запрос соседей ещё не выполнился, то ставим флаг, что по выполнению нужно сделать переход
							if (this.nextRecordPending) {
								this.immediatelySwitchToNext = true
							}
							else {
								this.showDetailView = false
								this.refreshList()
							}
						}
					}
					else
						this.refreshList()
					break

				case 'recordDeleted':
					this.needRefresh = true
					this.scrollPos = 0

					if (this.nextRecord !== null) {
						this.switchToRecord('next')
					}
					else {
						this.hideDetails()
					}
					break

				case 'nextRecord':
					this.nextRecord = ev.data.record
					this.nextRecordPending = false

					if (this.immediatelySwitchToNext) {
						this.immediatelySwitchToNext = false

						if (this.nextRecord !== null)
							this.switchToRecord('next')
						else {
							this.showDetailView = false
							this.refreshList()
						}
					}
					break

				case 'prevRecord':
					this.prevRecord = ev.data.record
					break

				case 'segments':
					if (ev.data.segments)
						this.segmentsList = ev.data.segments
					break

				// Экспорт не прошёл, потому что не указана волна
				case 'exportRejected-wave':
					this.pendingExport = false
					break

				case 'filterFilesList':
					if ('files' in ev.data)
						this.filterFilesList = ev.data.files
					break

				case 'exportRecords':
					this.pendingExport = false
					if (!ev.data.links.length)
						alert('Сервер вернул пустой список выгрузки')
					else
						this.exportLinks = this.exportLinks.concat(ev.data.links)
					break

				case 'badExport':
					this.pendingExport = false
					break

				// Информация по запрошенному штрихкоду
				case 'skuDetailInfo':
					this.recordDetails.sku.brand    = ev.data.sku.brand
					this.recordDetails.sku.name     = ev.data.sku.name
					this.recordDetails.sku.producer = ev.data.sku.producer
					this.recordDetails.sku.segment  = ev.data.sku.segment
					break

				// Пришли подсказки с производителями
				case 'producersSuggestions':
					if (this.showDetailView && this.recordDetails.id)
						this.$set(this.producersSuggestions, this.recordDetails.id, ev.data.producers)
					break

				// Перемещение записей из модерации в отправленные не удалось
				case 'badModerationSend':
					this.moderationSendPending = false
					alert('Не удалось переместить записи в отправленные')
					break

				// Записи перемещены из модерации в отправленные
				case 'moderationSent':
					this.moderationSendPending = false
					this.refreshList('resetPage')
					break
			}
		},

		// Объединение обычных фильтров с фильтрами из заголовков таблицы
		combinedFilters() {
			let ret = this.filters

			if (['moderation', 'sent'].indexOf(ret.tab) != -1)
				ret = Object.assign(ret, this.headerFilters)
			return ret
		},

		refreshList(resetPage) {
			if (this.token) {
				this.records = []
				this.totalRecordsSTR = '…'
				this.totalRecordsCount = 0
				this.needRefresh = false
				this.scrollPos = 0

				if (resetPage !== undefined && this.page !== 1)
					this.page = 1
				else
					window.worker.postMessage({
						type: this.type,
						page: this.page,
						pageSize: this.pageSize,
						token: this.token,
						filters: this.combinedFilters(),
						sorting: this.sorting
					})
			}
		},

		// Окончание для "записей"
		recWordEnd(rec) {
			const C10 = rec % 10
			const C100 = rec % 100
			let R

			if (C100 > 10 && C100 < 20 || C10 > 4 || C10 == 0) R = 'ей'
			else if (C10 == 1) R = 'ь'
			else R = 'и'

			return R
		},

		// Очистка фильтра
		/* Параметру tab доступны значения:
			sent       (отправленные)
			priceless  (без цены)
			moderation (модерация)
			toclient   (выгрузка клиенту)
		*/
		clearFilters(init) {
			this.filters = {
				dateFrom:   '',
				dateTo:     '',
				client:     -1,
				wave:       -1,
				net:        -1,
				auditor:    '',
				segment:    -1,
				priceNotChanged: 0,
				tradePoint: -1,
				tab: init === undefined ? this.filters.tab : 'sent'
			}
			this.filtersValues = {}

			if (init !== undefined && this.hasOnlyRole('auditor'))
				this.filters.tab = 'priceless'    // без цены

			this.switchAuditorsFilterVisibility()
			this.resetLists()
			this.showFilesFilter = this.filters.tab == 'toclient'

			Object.keys(this.headerFilters).forEach(K => {
				this.$set(this.headerFilters, K, '')
			})

			if (init === undefined)
				this.refreshList('resetPage')
		},

		// Установка данных для фильтра
		setFilter(data) {
			this.filters = Object.assign(this.filters, data)

			this.refreshList()
		},

		setFiltersValues(data) {
			this.filtersValues = data
		},

		setHeaderFilters(data) {
			this.headerFilters = data
		},

		// Сброс всех видимых полей таблицы
		setInVisibleFields(invisibleList) {
			if (invisibleList == undefined)
				invisibleList = []
			if (invisibleList.constructor.name != 'Array')
				invisibleList = [invisibleList]
			invisibleList.push('producer')

			this.visibleFields = {
				checkbox:    ['toclient', 'deleted'].indexOf(this.filters.tab) == -1,
				auditor:     !invisibleList.includes('auditor'),
				date:        !invisibleList.includes('date'),
				itemName:    !invisibleList.includes('itemName'),
				brand:       !invisibleList.includes('brand'),
				segment:     !invisibleList.includes('segment'),
				tradePoint:  !invisibleList.includes('tradePoint'),
				barCode:     !invisibleList.includes('barcode'),
				priceNormal: !invisibleList.includes('priceNormal'),
				priceByCard: !invisibleList.includes('priceByCard'),
				priceBySale: !invisibleList.includes('priceBySale'),
				client:      !invisibleList.includes('client'),
				wave:        !invisibleList.includes('wave'),
				net:         !invisibleList.includes('net'),
				percents:    ['sent', 'moderation'].indexOf(this.filters.tab) != -1,
				image:       true
			}
		},

		// Установка видимых пользователю полей в зависимости от роли
		setVFieldsToUser() {
			let invFilter = []

			if (this.filters.tab !== 'sent' && this.filters.tab !== 'moderation')
				invFilter.push('tradePoint')

			if (this.hasOnlyRole('auditor')) {
				invFilter = invFilter.concat(['auditor', 'brand', 'barcode', 'client', 'wave', 'net'])
			}
			else if (this.hasOnlyRole('coordinator') || this.hasOnlyRole('mentor')) {
				invFilter.push('date')
				// Есть поля, которые видны только на табе "выгрузка клиенту"
				if (this.filters.tab != 'toclient') {
					invFilter.push('brand')
					invFilter.push('barcode')
				}
			}

			this.setInVisibleFields(invFilter)
		},

		// Выбрать все строки
		checkAll(ev) {
			this.records.map(record => record.checked = ev.target.checked)
		},

		// Пересчёт числа отмеченных строк
		calcCheckedCount() {
			this.checkedCount = this.records.filter(rec => rec.checked).length
		},

		// Проверка, что установленный флаг "цена не изменилась", по факту актуален
		checkChangedPrice() {
			if (!this.recordDetails.price_not_changed) return

			if (this.recordDetails.previous_general_price != this.recordDetails.general_price
				|| this.recordDetails.previous_card_price != this.recordDetails.card_price
				|| this.recordDetails.previous_sale_price != this.recordDetails.sale_price)
			this.recordDetails.price_not_changed = false
		},

		// Переход на страницу
		gotoPage(page) {
			this.page = page
		},

		// Переключение таба
		changeTab(value) {
			if (value == this.filters.tab) return

			this.filters.tab = value
			this.setVFieldsToUser()
			this.switchAuditorsFilterVisibility()
			this.switchPricechangeFilter()
			this.showFilesFilter = value == 'toclient'

			this.refreshList('resetPage')
		},

		// Событие при смене клиента в фильтре
		chClient(client) {
			this.resetLists()
			window.worker.postMessage({
				type: 'wavesFilter',
				token: this.token,
				client: client
			})
		},

		// Событие при смене волны
		chWave(wave) {
			this.networksList    = []
			this.tradePointsRaw  = []
			this.selectedNetwork = null

			window.worker.postMessage({
				type: 'networks',
				token: this.token,
				wave: wave
			})
			window.worker.postMessage({
				type: 'tradePoints',
				token: this.token,
				wave: wave
			})
		},

		// Событие при смене сети
		chNetwork(net) {
			this.selectedNetwork = (net == -1 ? null : Number(net))
		},

		// Сброс фильтра
		resetLists() {
			this.wavesList       = []
			this.networksList    = []
			this.tradePointsRaw  = []
			this.selectedNetwork = null
		},

		// Отображение подробностей записи
		showDetails(idx) {
			this.scrollPos = window.scrollY
			this.recordDetails = this.records[idx]
			this.showDetailView = true
			this.prevRecord = null
			this.nextRecord = null
			window.scrollTo(0, 0)
			this.$nextTick(() => {
				const Inp = document.querySelector('.body > .prices .price.new .priceblock:first-child input')
				Inp && Inp.focus()
				if (this.recordDetails.sku.brand && this.filters.tab == 'moderation')
					this.loadProducersSuggestions(this.recordDetails.sku.brand)
			})

			this.nextRecordPending = true
			window.worker.postMessage({
				type: 'getRecordNeighbours',
				token: this.token,
				id: this.recordDetails.id,
				filters: this.combinedFilters(),
				sorting: this.sorting
			})
		},

		// Перейти обратно к полному списку
		hideDetails() {
			this.showDetailView = false
			if (this.needRefresh) {
				this.refreshList()
				this.needRefresh = false
			}

			if (this.scrollPos) {
				this.$nextTick(() => {
					window.scrollTo(0, this.scrollPos)
					this.scrollPos = 0
				})
			}
		},

		// Такая же функция есть в itemsTable
		getAuditorName(auditorObj) {
			const nameParts = []
			auditorObj.first_name && nameParts.push(auditorObj.first_name)
			auditorObj.last_name && nameParts.push(auditorObj.last_name)
			if (nameParts.length)
				return nameParts.join(' ')

			return ''
		},

		// Отображение большой картинки
		showImage(src) {
			this.showFullImage = true
			this.fullImageSrc = src
		},

		// Сохранение согласно ситуации
		saveAction() {
			if (this.showDetailView)
				this.saveRecordFromDetail()
			else
				this.saveRecords()
		},

		// Сохранение отмеченных данных
		saveRecords() {
			const data = []
			this.records.filter(rec => rec.checked).forEach(rec => {
				data.push(rec)
				rec.checked = false
			})
			window.worker.postMessage({
				type: 'saveRecords',
				token: this.token,
				records: data
			})
		},

		// Цена не изменилась
		priceNotChanged() {
			this.recordDetails.price_not_changed = true
			this.recordDetails.general_price = this.recordDetails.previous_general_price
			this.recordDetails.card_price = this.recordDetails.previous_card_price
			this.recordDetails.sale_price = this.recordDetails.previous_sale_price
			this.recordDetails.checked = true
		},

		// Сохранение одной записи из блока подробной информации
		saveRecordFromDetail() {
			if (this.recordDetails.previous_general_price != this.recordDetails.general_price
				|| this.recordDetails.previous_card_price != this.recordDetails.card_price
				|| this.recordDetails.previous_sale_price != this.recordDetails.sale_price)
				this.recordDetails.price_not_changed = false

			// Теперь в модерации можно редактировать sku, поэтому проверим, что sku изменилась
			const sku = this.recordDetails.sku
			if (sku.barcode == sku.srcBarcode
			    && (sku.brand != sku.srcBrand
			    || sku.producer != sku.srcProducer
			    || sku.segment.code != sku.srcSegment.code
			    || sku.name != sku.srcName)) {
					this.recordDetails.checked = true

					window.worker.postMessage({
						type: 'editSku',
						token: this.token,
						sku: sku
					})
			    }

			// Нужно чтобы была заполнена хотя бы одна цена
			if (this.detailSaveDisabled) {
				this.switchToInput('ordinary')
				return
			}

			window.worker.postMessage({
				type: 'saveRecords',
				token: this.token,
				records: [this.recordDetails],
				keepDetails: true
			})
		},

		// Переключение на запись в подробном виде
		switchToRecord(which) {
			if (which == 'next' && this.nextRecord)
				this.recordDetails = this.nextRecord
			else if (which == 'prev' && this.prevRecord)
				this.recordDetails = this.prevRecord
			else
				return

			this.$nextTick(() => {
				const Inp = document.querySelector('.body > .prices .price.new .priceblock:first-child input')
				Inp && Inp.focus()
				if (this.recordDetails.sku.brand && this.filters.tab == 'moderation')
					this.loadProducersSuggestions(this.recordDetails.sku.brand)
			})

			this.nextRecord = null
			this.prevRecord = null
			this.nextRecordPending = true
			window.worker.postMessage({
				type: 'getRecordNeighbours',
				token: this.token,
				id: this.recordDetails.id,
				filters: this.combinedFilters(),
				sorting: this.sorting
			})
		},

		deleteRecord() {
			if (!confirm('Действительно удалить?')) return

			window.worker.postMessage({
				type: 'deleteRecord',
				token: this.token,
				id: this.recordDetails.id
			})
		},

		switchAuditorsFilterVisibility() {
			this.showAuditorsFilter = !(this.hasOnlyRole('auditor') || this.filters.tab == 'toclient')
		},

		// Фильтр по "цена не изменилась"
		switchPricechangeFilter() {
			this.showPricechangeFilter = this.filters.tab == 'sent'
		},

		// Запрос выгрузки
		requestExport() {
			this.pendingExport = true
			window.worker.postMessage({
				type: 'exportRecords',
				token: this.token,
				filters: this.filtersValues
			})
		},

		// Переход курсора в другое поле
		switchToInput(fieldRef) {
			document.querySelector(`.price.new [name=${fieldRef}]`).focus()
		},

		// Очистка значений sku в подробном виде модерации
		clearItem() {
			if (this.recordDetails.sku.barcode != this.recordDetails.sku.srcBarcode) {
				this.recordDetails.sku.name     = ''
				this.recordDetails.sku.brand    = ''
				this.recordDetails.sku.producer = ''
			}
		},

		// Восстановление исходных значений sku в подробном виде модерации
		restoreItem(E) {
			E.stopPropagation()
			this.recordDetails.sku.barcode  = this.recordDetails.sku.srcBarcode
			this.recordDetails.sku.name     = this.recordDetails.sku.srcName
			this.recordDetails.sku.brand    = this.recordDetails.sku.srcBrand
			this.recordDetails.sku.producer = this.recordDetails.sku.srcProducer
			this.recordDetails.sku.segment  = this.recordDetails.sku.srcSegment
		},

		// Загрузка данных sku по штрихкоду (при смене штрихкода)
		loadBarcode() {
			if (this.recordDetails.sku.barcode != this.recordDetails.sku.srcBarcode) {
				this.clearItem()
				window.worker.postMessage({
					type: 'getSku',
					token: this.token,
					barcode: this.recordDetails.sku.barcode,
					idx: -1
				})
			}
			else this.restoreItem()
		},

		// Загрузка подсказок по производителям
		loadProducersSuggestions(brand) {
			if (brand && brand.length)
				window.worker.postMessage({
					type: 'producersByBrand',
					token: this.token,
					brand: brand,
					id: 0
				})
		},

		// Отправка всех записей из модерации в отправленные
		AllToSent() {
			if (!this.moderationSendPending && confirm('Переместить все записи?')) {
				this.moderationSendPending = true

				window.worker.postMessage({
					type: 'ModerationToSent',
					token: this.token,
					wave: this.filtersValues.wave
				})
			}
		},

		sortingChange(sortingValue) {
			this.sorting = sortingValue
			this.refreshList('resetPage')
		}
	},

	watch: {
		token(newToken) {
			if (newToken !== null && this.uRoles.length && this.refreshList)
				this.refreshList()
		},

		page() {
			this.refreshList()
		},

		filters() {
			this.calcCheckedCount()
		},

		records() {
			this.calcCheckedCount()
		}
	},

	computed: {
		pagesCount() {
			return Math.ceil(this.totalRecordsCount / this.pageSize)
		},

		// Окончание для 'записей'
		checkedWordEnd() {
			const C10 = this.checkedCount % 10
			const C100 = this.checkedCount % 100
			let S = 'о'

			if (C10 == 1 && C100 != 11) S = 'а'

			return S
		},

		// Фильтрованный список
		tradePointsList() {
			if (this.selectedNetwork === null) return this.tradePointsRaw
			return this.tradePointsRaw.filter(tp => tp.retail_network.id == this.selectedNetwork)
		},

		// Элементы для блока фильтров
		filterFields() {
			return [
				{
					type: 'date',
					name: 'dateFrom',
					placeholder: 'Дата с',
					row: 1,
					width: !this.showAuditorsFilter ? (this.showFilesFilter ? 1 : 2) : 1,
				},
				{
					type: 'date',
					name: 'dateTo',
					placeholder: 'Дата до',
					row: 1,
					width: !this.showAuditorsFilter ? (this.showFilesFilter ? 1 : 2) : 1,
				},
				{
					type: 'input',
					name: 'auditor',
					placeholder: 'Аудитор',
					row: 1,
					width: 2,
					invisible: !this.showAuditorsFilter,
					gridStart: 3,
					invisible: ['sent', 'moderation'].indexOf(this.filters.tab) != -1
				},
				{
					type: 'select',
					name: 'client',
					placeholder: 'Клиент',
					row: ['sent', 'moderation'].indexOf(this.filters.tab) != -1 ? 2 : 1,
					width: ['sent'].indexOf(this.filters.tab) != -1 ? 2 : 1,
					options: this.clientsList,
					placeholderDisabled: true
				},
				{
					type: 'select',
					name: 'filterByFile',
					placeholder: '-- Файл --',
					row: 1,
					width: 2,
					invisible: !this.showFilesFilter,
					options: this.filterFilesList,
					disabled: !this.filtersValues.wave || this.filtersValues.wave == -1
				},
				{
					type: 'select',
					name: 'priceNotChanged',
					placeholder: 'Цена любая',
					row: ['sent'].indexOf(this.filters.tab) != -1 ? 1: 2,
					width: 2,
					options: [{id: 1, name: 'Цена не изменилась'}],
					invisible: !this.showPricechangeFilter
				},
								{
					type: 'select',
					name: 'segment',
					placeholder: 'Сегмент',
					width: this.showPricechangeFilter ? 1 : 2,
					row: 2,
					options: this.segmentsList,
					invisible: ['sent', 'moderation'].indexOf(this.filters.tab) != -1
				},
				{
					type: 'select',
					name: 'net',
					placeholder: 'Все торговые сети',
					width: 2,
					row: 2,
					options: this.networksList,
					invisible: ['sent', 'moderation'].indexOf(this.filters.tab) != -1
				},
				{
					type: 'select',
					name: 'wave',
					placeholder: 'Волна',
					row: ['sent', 'moderation', 'toclient'].indexOf(this.filters.tab) != -1 ? 2 : 1,
					width: ['sent'].indexOf(this.filters.tab) != -1 ? 2 : 1,
					options: this.wavesList
				},
				{
					type: 'multiselect',
					name: 'tradePoint',
					placeholder: 'Все торговые точки',
					width: 2,
					row: 2,
					options: this.tradePointsList,
					invisible: ['sent', 'moderation'].indexOf(this.filters.tab) != -1
				},
				{
					type: 'reset',
					value: 'Очистить фильтры',
					width: 2,
					row: 1
				},
				{
					type: 'submit',
					value: 'Применить',
					width: 2,
					row: 2
				}
			]
		},

		// Список табов для верхнего фильтра
		tabs() {
			const ret = [
				{
					name: 'sent',
					value: 'Отправленные'
				},
				{
					name: 'priceless',
					value: 'Без цены'
				}
			]

			if (!this.hasOnlyRole('mentor')) {
				ret.push({
					name: 'moderation',
					value: 'Модерация'
				})
				ret.push({
					name: 'toclient',
					value: 'Выгрузка клиенту'
				})
			}

			if (this.hasOnlyRole('coordinator'))
				ret.push({
					name: 'deleted',
					value: 'Удалённые'
				})

			return ret
		},

		// Запрет сохранения в блоке деталей записи
		detailSaveDisabled() {
			return (this.recordDetails.general_price === '' || this.recordDetails.general_price === null)
				&& (this.recordDetails.card_price === '' || this.recordDetails.card_price === null)
				&& (this.recordDetails.sale_price === '' || this.recordDetails.sale_price === null)
		}
	}
}
</script>

<style lang="scss" scoped>
	$redColor: #eb1d1d;

	.body { display: table; min-width: 100%; }
	.pager {
		text-align: center;
		font-size: 16px;
	}
	section + .pager { margin-top: 24px; }

	.counter-pager-submit {
		margin-bottom: 24px;
		display: flex;
		position: relative;
		align-items: center;
		height: 50px;

		> * {
			display: flex;
			align-items: center;
		}

		.checkAll {
			user-select: none;
			margin-right: 32px;

			input {
				border: 1px solid var(--blueColor);
				display: inline-block;
				outline: none;
				margin-left: 12px;

				@media (max-width: 1440px) { margin-left: 8px; }
			}
			span {
				display: inline-block;
				margin-left: 24px;
