<template>
	<!-- ctrl+alt+"\" обновляет записи -->
	<div class="body">
		<div class="header" v-if="isAdmin">Список пользователей</div>
		<div class="header" v-else>Список аудиторов</div>
		<div class="filterline">
			<filterBlock class="usersShortFilter" :filterFields="filterFields" @reset="clearFilters" @submit="setFilter"/>
			<input type="button" class="addNew" @click="displayAddUserForm" value="Создать пользователя" title="[Alt + C]" v-if="isAdmin || isMentor">
		</div>
		<div class="counter-pager-submit">
			<span class="usersCount">{{ totalUsersSTR }}<span v-text="usersName"></span></span>
			<pager v-if="totalUsersCount > pageSize" :currentPage="page" :pagesCount="pagesCount" @changePage="gotoPage"/>
		</div>
		<section class="tableData">
			<div class="Uline caption">
				<div class="Ublock name">ФИО</div>
				<div class="Ublock mentor" v-if="isAdmin">Наставник</div>
				<div class="Ublock role" v-if="isAdmin">Роль</div>
				<div class="Ublock login">Логин</div>
				<div class="Ublock password">Пароль</div>
			</div>
			<div class="Uline" v-for="user in users">
				<div class="Ublock name">{{ buildUserName(user) }}</div>
				<div class="Ublock mentor" v-if="isAdmin">{{ getMentor(user) }}</div>
				<div class="Ublock role" v-if="isAdmin">{{ getRole(user) }}</div>
				<div class="Ublock login">{{ user.username }}</div>
				<div class="Ublock password"><button @click="showUser(user)">Изменить</button></div>
			</div>
			<div class="Uline" v-if="!users.length"><div class="Ublock name"><progress></progress></div></div>
		</section>
		<pager v-if="totalUsersCount > pageSize" :currentPage="page" :pagesCount="pagesCount" @changePage="gotoPage"/>

		<div class="overlay" v-if="this.changingUser !== null || appendUserData !== null" @click="hideUser">
			<div class="changeForm" @click.stop="">
				<div class="close" @click="hideUser"><img src="@/assets/img/close_cross.svg" alt="Закрыть"></div>
				<div class="abbrev" v-if="isChanging">{{ getRoleAbbrev(changingUser.groups[0].name) }}</div>
				<h3 class="fullName" v-if="isChanging">{{ changingUserFullname }}</h3>
				<div class="role" v-if="isChanging">Роль: <b>{{ changingUser.groups[0].name }}</b></div>
				<div v-else class="formTitle">Создание <i v-if="isAdmin">пользователя</i><i v-if="isMentor">аудитора</i></div>
				<div class="fields">
					<div class="field">
						<label :class="{hasError: appendUserErrorFields.indexOf('first_name') !== -1}">Имя</label>
						<input v-if="isChanging" type="text" v-model="changingUser.first_name">
						<input v-else type="text" v-model="appendUserData.first_name" placeholder="Укажите имя" required ref="newName">
					</div>
					<div class="field">
						<label :class="{hasError: appendUserErrorFields.indexOf('last_name') !== -1}">Фамилия</label>
						<input v-if="isChanging" type="text" v-model="changingUser.last_name">
						<input v-else type="text" v-model="appendUserData.last_name" placeholder="Укажите фамилию" required ref="newLastName">
					</div>
					<div class="field">
						<label>Отчество</label>
						<input v-if="isChanging" type="text" v-model="changingUser.middle_name" placeholder="Укажите отчество">
						<input v-else type="text" v-model="appendUserData.middle_name" placeholder="Укажите отчество" ref="newMiddleName">
					</div>
					<div class="field">
						<label>Наставник</label>
						<select v-if="isChanging" v-model="changingUser.mentorN" :disabled="hasOnlyRole('mentor')" @keyup.escape.stop="">
							<option value="-1">--</option>
							<option v-for="mentor in mentorsList" :value="mentor.id">{{ mentor.first_name + ' ' + mentor.last_name }}</option>
						</select>
						<select v-else v-model="appendUserData.mentorN" ref="newMentor" :disabled="appendUserData.group != 2 && appendUserData.group != -1 || isMentor" @keyup.escape.stop="">
							<option value="-1">--</option>
							<option v-for="mentor in mentorsList" :value="mentor.id">{{ mentor.first_name + ' ' + mentor.last_name }}</option>
						</select>
					</div>
					<div class="field">
						<label :class="{hasError: appendUserErrorFields.indexOf('group') !== -1}">Роль</label>
						<select v-if="isChanging" v-model="changingUser.group" :disabled="hasOnlyRole('mentor')" @keyup.escape.stop="">
							<option v-for="grp in userGroupsList" :value="grp.id">{{ grp.name }}</option>
						</select>
						<select v-else v-model="appendUserData.group" ref="newGroup" :disabled="isMentor" @keyup.escape.stop="">
							<option v-for="grp in userGroupsList" :value="grp.id">{{ grp.name }}</option>
						</select>
					</div>
					<div class="field row3">
						<label :class="{hasError: appendUserErrorFields.indexOf('login') !== -1}">Логин</label>
						<input v-if="isChanging" type="text" v-model.number="changingUser.username">
						<input v-else type="text" v-model="appendUserData.username" ref="newLogin" placeholder="9xxxxxxxxx" required pattern="^9\d{9}$">
						<i v-if="userExistsFlag">Пользователь существует</i>
					</div>
					<div class="field row3">
						<label :class="{hasError: appendUserErrorFields.indexOf('password') !== -1}">Пароль</label>
						<input v-if="isChanging" type="password" v-model="changingUser.password" ref="password" require maxlength="10">
						<input v-else type="password" v-model="appendUserData.password" ref="password" maxlength="10" required>
						<span class="switchPasswordVisibility" @click="switchPasswordVisibility" title="Показать/скрыть пароль"></span>
					</div>
					<div class="field row4">
						<label>&nbsp;</label>
						<button class="save" @click="createOrUpdateUser" title="[F2]">Сохранить</button>
					</div>
				</div>
			</div>
		</div>
	</div>
</template>

<script>
import filterBlock from '@/components/filterBlock'
import pager from '@/components/pager'
export default {
	components: {pager, filterBlock},
	created() {
		this.clearFilters('init')
		this.$store.dispatch('setLastPage', this.type)
	},

	data() {
		return {
			type: 'users',
			page: 1,
			users: [],
			filters: null,
			totalUsersSTR: '…',
			totalUsersCount: 0,

			filterFields: [
				{
					type: 'input',
					name: 'lastName',
					placeholder: 'Поиск по фамилии',
					width: 2,
					row: 1
				},
				{
					type: 'input',
					name: 'login',
					placeholder: 'Поиск по логину',
					width: 2,
					row: 1
				},
				{
					type: 'reset',
					value: 'Очистить фильтры',
					width: 2,
					row: 1
				},
				{
					type: 'submit',
					value: 'Применить',
					width: 2,
					row: 1
				}
			],

			mentorsList: [],
			changingUser: null,       // Структура пользователя, который редактируется
			changingUserFullname: '', // Чтобы не было излишне реактивно, делаем так
			appendUserData: null,     // Структура добавляемого пользователя
			appendUserErrorFields: [], // Поля формы добавления пользователя с ошибками
			userExistsFlag: false,    // Флаг, что пользователь уже существует
			userGroupsList: [],
			auditorRoleId: -1             // id аудитора для создания пользователя наставником
		}
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))

		if (!this.uRoles.length || !this.linksToDraw[this.type]) {
			location.hash = '#/splash'
			return
		}

		this.refreshList()
		window.worker.postMessage({
			type: 'mentors',
			token: this.token
		})

		// Запрос списка групп для создания пользователя
		window.worker.postMessage({
			type: 'userGroups',
			token: this.token
		})

		window.addEventListener('keyup', this.keyHandler, false)
		window.worker.addEventListener('message', this.workerHandler)
	},

	beforeDestroy() {
		window.removeEventListener('keyup', this.keyHandler)
		window.worker.removeEventListener('message', this.workerHandler)
	},

	methods: {
		keyHandler(E) {
			let M
			if (E.code == 'Escape' && !E.ctrlKey && !E.altKey && !E.shiftKey) {
				if (this.changingUser !== null || this.appendUserData !== null)
					this.hideUser()
			}

			else if(E.code == 'F2' && !E.ctrlKey && !E.altKey && !E.shiftKey) {
				if (this.changingUser !== null || appendUserData !== null)
					this.createOrUpdateUser()
			}

			// Быстрый переход по страницам
			else if (this.changingUser === null && E.ctrlKey && E.shiftKey && !E.altKey && (M = E.code.match(/^(?:Numpad|Digit)([0-9])$/))) {
				if (M[1] > 0)
					this.page = parseInt(M[1])
			}

			// Листалка страниц на ctrl+стрелки
			else if (E.ctrlKey && (E.code == 'ArrowLeft' || E.code == 'Numpad4') && !E.altKey && !E.shiftKey)
				this.goToPage(Math.max(0, this.page - 1))
			else if (E.ctrlKey && (E.code == 'ArrowRight' || E.code == 'Numpad6') && !E.altKey && !E.shiftKey)
				++this.page

			else if (E.ctrlKey && E.shiftKey && !E.altKey && (M = E.code.match(/^(?:Numpad|Digit)([0-9])$/))) {
				if (M[1] > 0)
					this.page = parseInt(M[1])
			}

			// Форма создания пользователя
			else if (E.code == 'KeyC' && E.altKey && !E.ctrlKey && !E.shiftKey) {
				if (this.changingUser == null)
					this.displayAddUserForm()
			}
		},

		workerHandler(ev) {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				case 'users':
					if (!ev.data.users) break
					if ('count' in ev.data.users) {
						'results' in ev.data.users && (this.users = ev.data.users.results)
						this.totalUsersCount = ev.data.users.count
					}
					else {
						this.users = ev.data.users
						this.totalUsersCount = this.users.length
					}
					this.totalUsersSTR = this.totalUsersCount.toString().replace(/(\d)(?=(\d{3})+\b)/g,'$1 ')
					break

				case 'mentors':
					if (ev.data.mentors)
						this.mentorsList = ev.data.mentors
					break

				case 'userGroups':
					if (ev.data.groups) {
						this.userGroupsList = ev.data.groups
						this.auditorRoleId =this.userGroupsList.filter(U => U.name == 'Аудитор')[0].id
					}
					break

				// Пользователь уже существует
				case 'userExists':
					this.appendUserErrorFields.push('login')
					this.$refs.newLogin.focus()
					this.userExistsFlag = true
					break

				// Плохой телефонный номер
				case 'userExists':
					this.appendUserErrorFields.push('login')
					this.$refs.newLogin.focus()
					break

				// Пользователь создан или изменён
				case 'userUpdated':
					this.appendUserData = null
					this.changingUser = null
					this.refreshList()
					window.worker.postMessage({
						type: 'mentors',
						token: this.token
					})
					break
			}
		},

		refreshList(resetPage) {
			if (this.token) {
				this.users = []

				if (resetPage !== undefined && this.page !== 1)
					this.page = 1
				else
					window.worker.postMessage({
						type: this.type,
						page: this.page,
						pageSize: this.pageSize,
						token: this.token,
						filters: this.filters,
						isMentor: !this.isAdmin
					})
			}
		},

		clearFilters(init) {
			this.filters = {
				lastName: '',
				login:    ''
			}

			if (init == undefined)
				this.refreshList('resetPage')
		},

		setFilter(data) {
			this.filters = Object.assign(this.filters, data)

			this.refreshList('resetPage')
		},

		gotoPage(page) {
			this.page = page
		},

		// Соединение полного имени пользователя из имени и фамилии
		buildUserName(user) {
			const U = [user.first_name]
			if (user.last_name.length) U.push(user.last_name)
			return U.join(' ')
		},

		// Извлечение роли пользователя из его данных (для администратора)
		getRole(user) {
			const ret = []
			user.groups.map(G => ret.push(G.name))
			return ret.join(', ')
		},

		// Извлечение наставника пользователя из его данных (для администратора)
		getMentor(user) {
			return user.mentor ? user.mentor.first_name + ' ' + user.mentor.last_name : '-'
		},

		getRoleAbbrev(role) {
			switch(role) {
				case 'Аудитор':       return 'АУ';
				case 'Наставник':     return 'НА';
				case 'Координатор':   return 'КО';
				case 'Администратор': return 'АД';
			}
		},

		// Показ формы изменения пользователя
		showUser(user) {
			user.password = user.password || ''
			this.appendUserData = null
			this.changingUser = user
			this.changingUser.group = this.userGroupsList.find(G => G.name == user.groups[0].name).id
			this.changingUser.mentorN = this.changingUser.mentor ? this.changingUser.mentor.id : -1
			this.changingUserFullname = this.buildUserName(user)
		},

		hideUser() {
			this.changingUser = null
			this.appendUserData = null
			this.changingUserFullname = ''
		},

		// Смена типа поля с паролем
		switchPasswordVisibility() {
			this.$refs.password.type = ['password', 'text'][+(this.$refs.password.type == 'password')]
		},

		displayAddUserForm() {
			if (!this.isAdmin && !this.isMentor) return
			this.appendUserData = {
				username:    '',
				first_name:  '',
				last_name:   '',
				middle_name: '',
				password:    '',
				group:       -1,
				mentorN:     -1
			}

			if (this.isMentor) {
				this.appendUserData.mentorN = this.$store.getters.getUserId
				this.appendUserData.group = this.auditorRoleId
			}

			this.$nextTick(() => {
				this.$refs.newName.focus()
				this.$refs.newLogin.maxLength = 10
			})
		},

		// Валидация формы добавления пользователя
		validateNewUser() {
			this.appendUserErrorFields = []
			this.userExistsFlag = false

			if (!this.appendUserData.password.length) {
				this.appendUserErrorFields.push('password')
				this.$refs.password.focus()
			}

			if (!this.appendUserData.username.length || !/^9\d{9}$/.test(this.appendUserData.username)) {
				this.appendUserErrorFields.push('login')
				this.$refs.newLogin.focus()
			}

			if (this.appendUserData.group == -1) {
				this.appendUserErrorFields.push('group')
				this.$refs.newGroup.focus()
			}

			if (!this.appendUserData.last_name.length) {
				this.appendUserErrorFields.push('last_name')
				this.$refs.newLastName.focus()
			}

			if (!this.appendUserData.first_name.length) {
				this.appendUserErrorFields.push('first_name')
				this.$refs.newName.focus()
			}

			if (this.appendUserErrorFields.length) return false

			return true
		},

		createOrUpdateUser() {
			if (!this.isChanging && !this.validateNewUser()) return

			window.worker.postMessage({
				type: 'createOrUpdateUser',
				token: this.token,
				method: this.isChanging ? 'update' : 'create',
				user: this.isChanging ? this.changingUser : this.appendUserData
			})
		}
	},

	watch: {
		token(newToken) {
			if (newToken !== null && this.uRoles.length && this.refreshList)
				this.refreshList()
		},

		page() {
			this.refreshList()
		}
	},

	computed: {
		pagesCount() {
			return Math.ceil(this.totalUsersCount / this.pageSize)
		},

		usersName() {
			return this.isAdmin ? ' пользовател' + this.usersWordEnd.U : ' аудитор' + this.usersWordEnd.A
		},

		usersWordEnd() {
			const C10 = this.totalUsersCount % 10
			const C100 = this.totalUsersCount % 100
			let A = ''
			let U = ''

			if (C100 > 10 && C100 < 20 || C10 > 4 || C10 == 0) { A = 'ов', U = 'ей' }
			else if (C10 == 1) U = 'ь'
			else { A = 'а', U = 'я' }

			return {A, U}
		},

		isAdmin() {
			return this.hasOnlyRole('admin')
		},

		isMentor() {
			return this.hasOnlyRole('mentor')
		},

		// true, если пользователь редактируется и false, если создаётся. null — ни то ни другое
		isChanging() {
			return this.changingUser !== null || (this.appendUserData == null ? null: false)
		}
	}
}
</script>

