<template>
	<!-- ctrl+alt+"\" обновляет записи -->
	<div class="body" v-if="!showDetailView">
		<div class="header">SKU</div>
		<tabLine :tabs="tabs" :initialTab="filters.tab" @change="changeTab"/>
		<div class="filterline">
			<filterBlock :filterFields="filterFields" :disableDate="filters.tab == 'fullbase'" @reset="clearFilters" @submit="setFilter" @currentFilter="setFiltersValues"/>
			<input type="button" class="addNew" @click="displayAddForm" value="Добавить SKU" title="[Alt + C]">
		</div>
		<div class="counter-pager-submit">
			<label class="checkAll" v-if="filters.tab == 'noitem'">
				<input type="checkbox" @change="checkAll($event)" :key="'p' + page">
				<span>Выбрать все</span>
			</label>
			<span class="skuCount">{{ totalSkuSTR }} записей</span>
			<span class="selected" v-if="checkedCount">Выбран{{ skuWordEnd.S }} {{ checkedCount }} запис{{ skuWordEnd.R }}</span>
			<pager v-if="totalSkuCount > pageSize" :currentPage="page" :pagesCount="pagesCount" @changePage="gotoPage"/>
			<button class="submit" v-if="checkedCount" @click="saveChanges" title="[F2]">Отправить данные</button>
		</div>
		<itemsTable class="skuTables" :list="skuListForTable" :type="type" :subType="filters.tab" :segments="segmentsList" :visibleFields="visibleFields" @showDetails="filters.tab == 'fullbase' ? selectRow : showDetails" @imgClick="showDetails" @moreButtonPressed="showDetails" @brandChanged="loadProducersSuggestions" :producersSuggestions="producersSuggestions"/>
		<pager v-if="totalSkuCount > pageSize" :currentPage="page" :pagesCount="pagesCount" @changePage="gotoPage"/>

		<div class="overlay" v-if="showAddForm">
			<div class="addForm">
				<span class="close" @click="showAddForm = false" title="[Escape]"><img src="@/assets/img/close_cross.svg"></span>
				<div class="title">Создание SKU</div>
				<form>
					<div class="inputs">
						<div :class="{inputBlock: true, withError: addForm.errors.itemName}">
							<label>Название товара</label>
							<input type="text" placeholder="Укажите название" v-model="addForm.itemName" ref="newitemName">
						</div>
						<div :class="{inputBlock: true, center: true, withError: addForm.errors.segment}">
							<label>Сегмент</label>
							<select v-model="addForm.segment" ref="newsegment">
								<option disabled selected value="-1">Выберите сегмент</option>
								<option v-for="seg in segmentsList" :value="seg.code">{{ seg.name }}</option>
							</select>
						</div>
						<div :class="{inputBlock: true, withError: addForm.errors.brand}">
							<label>Бренд</label>
							<input type="text" placeholder="Укажите бренд" v-model="addForm.brand" ref="newbrand">
						</div>
						<div :class="{inputBlock: true, withError: addForm.errors.barcode}">
							<label>Штрихкод</label>
							<input type="text" placeholder="Укажите штрихкод" v-model="addForm.barcode" maxlength="13" ref="newbarcode">
						</div>
						<div :class="{inputBlock: true, center: true, withError: addForm.errors.producer}">
							<label>Производитель</label>
							<input type="text" placeholder="Укажите производителя" v-model="addForm.producer" ref="newproducer">
						</div>
					</div>
					<div class="error" v-if="addForm.errorText.length">{{ addForm.errorText }}</div>
					<div>
						<input type="button" class="submit" value="Сохранить" @click="addSku">
					</div>
				</form>
			</div>
		</div>
	</div>

	<div class="body detail" v-else :key="recordDetails.id ? recordDetails.id : 0">
		<div class="header">
			<div class="backButton" @click="hideDetails" title="[Escape]"><img src="@/assets/img/back.svg">назад</div>
			Подробная информация
		</div>
		<div class="buttons">
			<div class="arrows">
				<div :class="{arrow: true, left: true, disabled: !prevRecord}" @click="switchToRecord('prev')" title="Предыдущая запись [Ctrl + ←]"></div>
				<div :class="{arrow: true, right: true, disabled: !nextRecord}" @click="switchToRecord('next')" title="Следующая запись [Ctrl + →]"></div>
			</div>
			<div class="redButtons">
				<button class="redButton transparent" title="[Ctrl + Del]" @click="deleteRecord"><img src="@/assets/img/trash.svg" alt="">Удалить запись</button>
				<button class="redButton" title="[F2]" @click="saveDetailsChanges" v-if="filters.tab != 'fullbase'">Отправить данные</button>
			</div>
		</div>
		<table class="item">
			<tr>
				<th>Бренд</th>
				<th>Производитель</th>
				<th>Сегмент</th>
				<th>Название товара</th>
				<th>Штрихкод</th>
				<th>Аудитор</th>
				<th>Сеть</th>
				<th>Адрес</th>
				<th class="wider"></th>
			</tr>
			<tr v-if="recordDetails.auditor">
				<td class="brand"><customInput v-model="recordDetails.sku.brand" :readonly="recordDetails.sku.barcode != recordDetails.sku.srcBarcode" textField="true" @change="loadProducersSuggestions(recordDetails.sku.brand)"/></td>
				<td class="producer">
					<customInput v-model="recordDetails.sku.producer" :readonly="recordDetails.sku.barcode != recordDetails.sku.srcBarcode" textField="true" :list="'pr' + recordDetails.id"/>
					<datalist v-if="producersSuggestions[recordDetails.id] && producersSuggestions[recordDetails.id].length" :id="'pr' + recordDetails.id">
						<option v-for="sug of producersSuggestions[recordDetails.id]" :value="sug"/>
					</datalist>
				</td>
				<td class="segment">
					<select v-model="recordDetails.sku.segment.code" :disabled="segmentsList === undefined || !segmentsList.length || recordDetails.sku.barcode != recordDetails.sku.srcBarcode">
						<option v-for="seg in segmentsList" :value="seg.code">{{ seg.name }}</option>
					</select>
				</td>
				<td class="itemName"><customInput v-model="recordDetails.sku.name" :readonly="recordDetails.sku.barcode != recordDetails.sku.srcBarcode" textField="true"/></td>
				<td class="barcode"><customInput v-model="recordDetails.sku.barcode" maxlength="13" textField="true" @change="loadBarcode" @input="clearItem" @keydown.enter="loadBarcode" @keydown.esc="restoreItem" title="[Enter] — загрузить SKU по штрихкоду, [Esc] — вернуть исходные данные" ref="barcode"/></td>
				<td class="auditor">{{ getAuditorName(recordDetails.auditor) }}</td>
				<td class="net">{{ recordDetails.shop && recordDetails.shop.retail_network.name }}</td>
				<td class="tradePoint">{{ recordDetails.shop && recordDetails.shop.address }}</td>
				<td class="wider"></td>
			</tr>
		</table>
		<div class="images" v-if="recordDetails.auditor">
			<rotatingImg :src="recordDetails.barcode_photo.photo" @click="showImage(recordDetails.barcode_photo.photo)"/>
			<rotatingImg :src="recordDetails.price_photo.photo" @click="showImage(recordDetails.price_photo.photo)"/>
			<rotatingImg v-for="photo in recordDetails.other_photos" :src="photo.photo" @click="showImage(photo.photo)"/>
		</div>

		<div class="overlay clickable" v-if="showFullImage" @click="showFullImage = false">
			<img class="fullimage" :src="fullImageSrc" alt="" @click.stop="">
		</div>
	</div>
</template>

<script>
import itemsTable from '@/components/itemsTable'
import pager from '@/components/pager'
import tabLine from '@/components/tabLine'
import filterBlock from '@/components/filterBlock'
import customInput from '@/components/input'
import rotatingImg from '@/components/rotatingImg'
export default {
	components: {itemsTable, pager, tabLine, filterBlock, customInput, rotatingImg},

	data() {
		return {
			type: 'sku',
			skuList: [],
			page: 1,
			totalSkuSTR: '…',
			totalSkuCount: 0,

			// Значения полей фильтра
			filters: null,
			// Видимые поля в таблице
			visibleFields: null,

			// Список табов для верхнего фильтра
			tabs: [
				{
					name: 'fullbase',
					value: 'База SKU'
				},
				{
					name: 'noitem',
					value: 'Товар не верен'
				},
				{
					name: 'nobarcode',
					value: 'Штрихкода нет в базе'
				}
			],

			addForm: {
				itemName:  '',
				segment:   -1,
				brand:     '',
				barcode:   '',
				producer:  '',
				errorText: '',
				errors:    {
					itemName: false,
					segment:  false,
					brand:    false,
					barcode:  false,
					producer: false
				},
				pending: false   // Запрос отправляется
			},

			segmentsList: [],
			showAddForm: false,
			showFullImage: false,
			fullImageSrc: '',
			netsList: [],       // Список сетей для фильтра
			filtersValues: {},  // Текущее состояние фильтров, без применения

			nextRecord: null,
			prevRecord: null,
			showDetailView: false,
			needRefresh: false,
			recordDetails: {},

			producersSuggestions: {},    // Подсказки для списка производителей
			nextRecordPending: false,
			immediatelySwitchToNext: false
		}
	},

	created() {
		this.clearFilters('init')
		this.setInVisibleFields()
		this.$store.dispatch('setLastPage', this.type)
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))

		if (!this.uRoles.length || !this.linksToDraw[this.type]) {
			location.hash = '#/splash'
			return
		}

		// Загрузка списка сегментов для фильтра
		window.worker.postMessage({
			type: 'segments',
			token: this.token
		})

		// Загрузка названий всех сетей для фильтра
		window.worker.postMessage({
			type: 'all_networks',
			token: this.token
		})

		window.addEventListener('keyup', this.keyHandler, false)
		window.worker.addEventListener('message', this.workerHandler)

		this.refreshList()
	},

	beforeDestroy() {
		window.removeEventListener('keyup', this.keyHandler)
		window.worker.removeEventListener('message', this.workerHandler)
	},

	watch: {
		token(newToken) {
			if (newToken !== null && this.uRoles.length && this.refreshList)
				this.refreshList()
		},

		page() {
			this.refreshList()
		}
	},

	methods: {
		keyHandler(E) {
			let M
			if (E.code == 'Escape' && !E.ctrlKey && !E.altKey && !E.shiftKey) {
				if (this.$refs.barcode && E.target == this.$refs.barcode.$el)
					return

				if (this.showFullImage)
					this.showFullImage = false
				else if (this.showAddForm)
					this.showAddForm = false
				else
					this.hideDetails()
			}

			else if (E.code == 'Backslash' && E.ctrlKey && E.altKey && !E.shiftKey) {
				this.refreshList()
			}

			else if (E.code == 'KeyC' && E.altKey && !E.shiftKey && !E.ctrlKey)
				this.displayAddForm()

			else if (E.code == 'F2' && !E.ctrlKey && !E.altKey && !E.shiftKey) {
				if (this.showDetailView)
					this.saveDetailsChanges()
				else
					this.saveChanges()
			}


			// Листалка страниц на ctrl+стрелки
			else if (E.ctrlKey && (E.code == 'ArrowLeft' || E.code == 'Numpad4') && !E.altKey && !E.shiftKey) {
				if (!this.showDetailView)
					this.gotoPage(Math.max(0, this.page - 1))
				else
					this.switchToRecord('prev')
			}
			else if (E.ctrlKey && (E.code == 'ArrowRight' || E.code == 'Numpad6') && !E.altKey && !E.shiftKey) {
				if (!this.showDetailView)
					++this.page
				else
					this.switchToRecord('next')
			}

			// Удаление записи
			else if ((E.code == 'Delete' || E.code == 'NumpadDecimal') && E.ctrlKey && !E.altKey && !E.shiftKey)
				this.deleteRecord()

			// Быстрый переход по страницам
			else if (!this.showDetailView && E.ctrlKey && E.shiftKey && !E.altKey && (M = E.code.match(/^(?:Numpad|Digit)([0-9])$/))) {
				if (M[1] > 0)
					this.page = parseInt(M[1])
			}
		},

		workerHandler(ev) {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				case 'sku':
					if (ev.data.sku) {
						let totalSku = 0
						if (ev.data.sku) {
							this.skuList = ev.data.sku
							totalSku = Number(ev.data.count)
						}
						this.totalSkuCount = totalSku
						this.totalSkuSTR = this.totalSkuCount.toString().replace(/(\d)(?=(\d{3})+\b)/g,'$1 ')
					}
					break

				case 'segments':
					if (ev.data.segments)
						this.segmentsList = ev.data.segments
					break

				case 'skuAdded':
					this.addForm.pending = false
					this.addForm.itemName  = ''
					this.addForm.segment   = -1
					this.addForm.brand     = ''
					this.addForm.barcode   = ''
					this.addForm.producer  = ''
					this.showAddForm = false
					this.clearAddFormErrors()

					if (this.filters.tab == 'fullbase')
						this.refreshList()
					break

				case 'addFormError':
					if (ev.data.field && ev.data.error) {
						this.addForm.pending = false
						this.addForm.errors[ev.data.field] = true
						this.addForm.errorText = ev.data.error
						if (this.$refs['new' + ev.data.field])
							this.$refs['new' + ev.data.field].focus()
					}
					break

				case 'skuChanged':
					if (ev.data.keepDetails) {
						this.needRefresh = true
						if (this.nextRecord !== null)
							this.switchToRecord('next')
						else {
							// Если запрос соседей ещё не выполнился, то ставим флаг, что по выполнению нужно сделать переход
							if (this.nextRecordPending) {
								this.immediatelySwitchToNext = true
							}
							else {
								this.showDetailView = false
								this.refreshList()
							}
						}
					}
					else
						this.refreshList()
					break

				case 'recordDeleted':
					this.needRefresh = true

					if (this.nextRecord !== null) {
						this.switchToRecord('next')
					}
					else {
						this.hideDetails()
					}
					break

				case 'nextRecord':
					this.nextRecord = ev.data.record
					this.nextRecordPending = false
					
					if (this.immediatelySwitchToNext) {
						this.immediatelySwitchToNext = false

						if (this.nextRecord !== null)
							this.switchToRecord('next')
						else {
							this.showDetailView = false
							this.refreshList()
						}
					}
					break

				case 'prevRecord':
					this.prevRecord = ev.data.record
					break

				case 'skuDetailInfo':
					this.recordDetails.sku.brand    = ev.data.sku.brand
					this.recordDetails.sku.name     = ev.data.sku.name
					this.recordDetails.sku.producer = ev.data.sku.producer
					this.recordDetails.sku.segment  = ev.data.sku.segment
					break

				// Пришли подсказки с производителями
				case 'producersSuggestions':
					if (ev.data.brandId)
						this.$set(this.producersSuggestions, ev.data.brandId, ev.data.producers)
					else if (this.showDetailView && this.recordDetails.id)
						this.$set(this.producersSuggestions, this.recordDetails.id, ev.data.producers)
					break

				case 'all_networks':
					if ('nets' in ev.data)
						this.netsList = ev.data.nets
					break
			}
		},

		refreshList(resetPage) {
			if (this.token) {
				this.skuList = []
				this.totalSkuSTR = '…'
				this.totalSkuCount = 0

				if (resetPage !== undefined && this.page !== 1)
					this.page = 1
				else
					window.worker.postMessage({
						type: this.type,
						page: this.page,
						pageSize: this.pageSize,
						token: this.token,
						filters: this.filters
					})
			}
		},

		// Такая же функция есть в itemsTable
		getAuditorName(auditorObj) {
			const nameParts = []
			auditorObj.first_name && nameParts.push(auditorObj.first_name)
			auditorObj.last_name && nameParts.push(auditorObj.last_name)
			if (nameParts.length)
				return nameParts.join(' ')

			return ''
		},

		// Очистка фильтра
		/* Параметру tab доступны значения:
			fullbase  (все sku)
			noitem    (товар не верен)
			nobarcode (нет штрихкода в базе)
		*/
		clearFilters(init) {
			this.filters = {
				segment:  -1,
				brand:    '',
				producer: '',
				barcode:  '',
				tab: init !== undefined ? 'fullbase' : this.filters.tab
			}
			this.filtersValues = {}

			if (this.hasOnlyRole('auditor'))
				this.filters.tab = 'priceless'    // без цены

			if (init === undefined)
				this.refreshList('resetPage')
		},

		// Переключение табов
		changeTab(value) {
			if (value == this.filters.tab) return

			if (Object.keys(this.filtersValues).length)
				Object.keys(this.filtersValues).forEach(F => {
					this.filters[F] = this.filtersValues[F]
				})

			this.filters.tab = value
			this.setInVisibleFields()

			this.refreshList('resetPage')
		},

		// Выбрать все строки
		checkAll(ev) {
			this.skuList.map(sku => sku.checked = ev.target.checked)
		},

		// Переход на страницу
		gotoPage(page) {
			this.skuList = []
			this.page = page
		},

		// Отправка изменений на сервер
		saveChanges() {
			window.worker.postMessage({
				type: 'saveSku',
				token: this.token,
				list: this.skuListForTable,
				filter: this.filters.tab
			})
		},

		// Сохранение в окне подробностей
		saveDetailsChanges() {
			this.recordDetails.checked = true
			window.worker.postMessage({
				type: 'saveSku',
				token: this.token,
				list: [this.recordDetails],
				filter: this.filters.tab,
				keepDetails: true
			})
		},

		// Сброс всех видимых полей таблицы
		setInVisibleFields(invisibleList) {
			if (invisibleList == undefined)
				invisibleList = []
			if (invisibleList.constructor.name != 'Array')
				invisibleList = [invisibleList]

			this.visibleFields = {
				checkbox:    this.filters.tab == 'noitem',
				auditor:     false,
				date:        false,
				itemName:    this.filters.tab != 'nobarcode',
				brand:       this.filters.tab != 'nobarcode',
				segment:     this.filters.tab != 'nobarcode',
				barCode:     true,
				priceNormal: false,
				priceByCard: false,
				priceBySale: false,
				client:      false,
				wave:        false,
				net:         false,
				producer:    this.filters.tab != 'nobarcode',
				image:       this.filters.tab != 'fullbase',
				noBarCodeAuditor:    this.filters.tab == 'nobarcode',
				noBarCodeNet:        this.filters.tab == 'nobarcode',
				noBarCodeTradePoint: this.filters.tab == 'nobarcode'
			}
		},

		// Установка данных для фильтра
		setFilter(data) {
			this.filters = Object.assign(this.filters, data)

			this.refreshList('resetPage')
		},
		
		// Получение текущих значений фильтра без его применения
		setFiltersValues(data) {
			this.filtersValues = data
		},

		// Выбор строки при клике по названию или картинке
		selectRow(idx) {
			if (this.filters.tab != 'fullbase')
				this.skuList[idx].checked = !this.skuList[idx].checked
			console.info(idx)
		},

		// Отображение фотографии в большом размере
		showBigImage(idx) {
			this.fullImageSrc = this.skuList[idx].price_photo.photo
			this.showFullImage = true
		},

		// Отображение формы добавления
		displayAddForm() {
			this.showAddForm = true
			this.$nextTick(() => { if (this.$refs.newitemName !== undefined) this.$refs.newitemName.focus() })
		},

		// Очистка сообщений об ошибках в форме добавления SKU
		clearAddFormErrors() {
			this.addForm.errorText = ''
			Object.getOwnPropertyNames(this.addForm.errors).forEach(F => this.addForm.errors[F] = false)
		},

		// Валидация формы добавления
		validateAddForm() {
			this.clearAddFormErrors()
			let ret = true
			Object.getOwnPropertyNames(this.addForm.errors).forEach(F => {
				if (F == 'segment' && this.addForm.segment == -1
					|| F != 'segment' && !this.addForm[F].toString().length
					|| F == 'barcode' && isNaN(Number(this.addForm[F]))
				) {
						if (ret) this.$refs['new' + F].focus()
						this.addForm.errors[F] = true
						ret = false
				}
			})

			return ret
		},

		// Добавлене нового SKU, данные находятся в this.addForm
		addSku() {
			if (this.addForm.pending) return

			if (this.validateAddForm()) {
				this.addForm.pending = true
				window.worker.postMessage({
					type: 'addSku',
					token: this.token,
					formData: this.addForm
				})
			}
		},

		// Отображение подробностей записи
		showDetails(idx) {
			this.recordDetails = this.skuList[idx]
			this.showDetailView = true
			this.prevRecord = null
			this.nextRecord = null
			window.scrollTo(0, 0)

			this.nextRecordPending = true
			window.worker.postMessage({
				type: 'getRecordNeighbours',
				token: this.token,
				id: this.recordDetails.id,
				filters: this.filters
			})
		},

		// Перейти обратно к полному списку
		hideDetails() {
			this.showDetailView = false
			if (this.needRefresh)
				this.refreshList()
			this.needRefresh = false
		},

		saveRecordFromDetail() {
			window.worker.postMessage({
				type: 'saveRecords',
				token: this.token,
				records: [this.recordDetails],
				keepDetails: true
			})
		},

		// Переключение на запись в подробном виде
		switchToRecord(which) {
			if (which == 'next' && this.nextRecord)
				this.recordDetails = this.nextRecord
			else if (which == 'prev' && this.prevRecord)
				this.recordDetails = this.prevRecord
			else
				return

			this.$nextTick(() => {
				const Inp = document.querySelector('.body > .prices .price.new .priceblock:first-child input')
				Inp && Inp.focus()
			})

			this.nextRecord = null
			this.prevRecord = null
			this.nextRecordPending = true
			window.worker.postMessage({
				type: 'getRecordNeighbours',
				token: this.token,
				id: this.recordDetails.id,
				filters: this.filters
			})
		},

		deleteRecord() {
			if (!confirm('Действительно удалить?')) return

			window.worker.postMessage({
				type: 'deleteRecord',
				token: this.token,
				id: this.recordDetails.id
			})
		},

		showImage(src) {
			this.showFullImage = true
			this.fullImageSrc = src
		},

		// Очистка значений sku
		clearItem() {
			if (this.recordDetails.sku.barcode != this.recordDetails.sku.srcBarcode) {
				this.recordDetails.sku.name     = ''
				this.recordDetails.sku.brand    = ''
				this.recordDetails.sku.producer = ''
			}
		},

		// Восстановление исходных значений sku
		restoreItem(E) {
			this.recordDetails.sku.barcode  = this.recordDetails.sku.srcBarcode
			this.recordDetails.sku.name     = this.recordDetails.sku.srcName
			this.recordDetails.sku.brand    = this.recordDetails.sku.srcBrand
			this.recordDetails.sku.producer = this.recordDetails.sku.srcProducer
			this.recordDetails.sku.segment  = this.recordDetails.sku.srcSegment
		},

		// Загрузка данных sku по штрихкоду (при смене штрихкода)
		loadBarcode() {
			if (this.recordDetails.sku.barcode != this.recordDetails.sku.srcBarcode) {
				this.clearItem()
				window.worker.postMessage({
					type: 'getSku',
					token: this.token,
					barcode: this.recordDetails.sku.barcode,
					idx: -1
				})
			}
			else this.restoreItem()
		},

		// Загрузка подсказок по производителям
		loadProducersSuggestions(idx_brand) {
			let brand
			if (typeof idx_brand == 'string')
				brand = idx_brand
			else
				brand = this.skuList[idx_brand].sku.brand
			if (brand && brand.length)
				window.worker.postMessage({
					type: 'producersByBrand',
					token: this.token,
					brand: brand,
					id: (typeof idx_brand == 'number') ? this.skuList[idx_brand].id: 0
				})
		}
	},

	computed: {
		pagesCount() {
			return Math.ceil(this.totalSkuCount / this.pageSize)
		},

		// Количество отмеченных записей
		checkedCount() {
			if (this.filters.tab == 'fullbase' || this.filters.tab == 'nobarcode') return 0
			return this.skuList.filter(rec => rec.checked).length
		},

		// Окончание для 'записей'
		skuWordEnd() {
			const C10 = this.checkedCount % 10
			const C100 = this.checkedCount % 100
			let R
			let S = 'о'

			if (C100 > 10 && C100 < 20 || C10 > 4 || C10 == 0) R = 'ей'
			else if (C10 == 1) R = 'ь'
			else R = 'и'

			if (C10 == 1 && C100 != 11) S = 'а'

			return {S, R}
		},

		// Массив, выводимый на страницу
		skuListForTable() {
			if (!this.skuList.length) return []
			if (this.filters.tab != 'fullbase') return this.skuList

			return this.skuList.map(S => {
				S.sku = {
					brand:    S.brand,
					name:     S.name,
					barcode:  S.barcode,
					segment:  S.segment,
					producer: S.producer
				}

				return S
			})
		},

		// Элементы для блока фильтров
		filterFields() {
			return [
				{
					type: 'date',
					name: 'dateFrom',
					placeholder: 'Дата с',
					row: 1,
					invisible: this.filters.tab == 'fullbase'
				},
				{
					type: 'date',
					name: 'dateTo',
					placeholder: 'Дата до',
					row: 1,
					invisible: this.filters.tab == 'fullbase'
				},
				{
					type: 'select',
					name: 'segment',
					placeholder: 'Сегмент',
					row: 1,
					width: this.filters.tab == 'fullbase' || this.filters.tab == 'nobarcode' ? 2 : 1,
					options: this.segmentsList
				},
				{
					type: 'input',
					name: 'brand',
					placeholder: 'Бренд',
					row: 1,
					width: this.filters.tab == 'fullbase' ? 2 : 1,
					invisible: this.filters.tab == 'nobarcode'
				},
				{
					type: 'select',
					name: 'net',
					placeholder: '-- Сеть --',
					row: 1,
					options: this.netsList,
					invisible: this.filters.tab != 'nobarcode'
				},
				{
					type: 'reset',
					value: 'Очистить фильтры',
					width: 2,
					row: 1
				},
				{
					type: 'input',
					name: 'barcode',
					placeholder: 'Поиск по штрихкоду',
					row: 2,
					width: 2
				},
				{
					type: 'input',
					name: 'town',
					placeholder: 'Город',
					row: 2,
					width: 2,
					invisible: this.filters.tab != 'nobarcode'
				},
				{
					type: 'input',
					name: 'auditor',
					placeholder: 'Аудитор',
					row: 2,
					invisible: this.filters.tab != 'nobarcode'
				},
				{
					type: 'input',
					name: 'producer',
					placeholder: 'Производитель',
					row: 2,
					width: 2,
					invisible: this.filters.tab == 'nobarcode'
				},
				{
					type: 'submit',
					value: 'Применить',
					width: 2,
					row: 2
				}
			]
		}
	}
}
</script>

