<template>
	<!--
		Параметры, принимаемые в объекте массива filterFields:
		    type: тип поля (date, input, select, reset, submit)
		    name: имя поля, отдаваемое в submit
		    placeholder: placeholder в инпуте или значение по умолчанию для select (первый элемент)
		    width: количество занимаемых ячеек сетки (по умолчанию 1)
		    row: строка, в которой следует разместить элемент
		    options: массив объектов для options в select
		    placeholderDisabled: если true, то значение первого option в select будет недоступно для ручного выбора
		    value: надпись на кнопках reset и submit,
		    disableDate: когда нужно отключить фильтр с датой
		    disabled: сделать select неактивным
		    invisible: невидимый фильтр. Нужно для скрытия без потери введённых данных
		    gridStart: костыльный параметр для установки grid-column-start
	-->
	<form class="filterBlock" data-filterform="this" v-on:submit.prevent="submitForm">
		<div v-for="elem in filterFields" :class="{wide: elem.width == 2, ultrawide: elem.width == 3, ml: elem.type == 'reset' || elem.type == 'submit'}" v-show="!elem.invisible" :style="{'grid-column-start': elem.gridStart, 'grid-row': elem.row}">
			<input type="text" :name="elem.name" v-if="elem.type == 'input'" :placeholder="elem.placeholder || ''" @change="u">
			<Datepicker :disabled="disableDate == true" :language="ru" format="dd.MM.yyyy" :name="elem.name" v-if="elem.type == 'date'" :placeholder="elem.placeholder || ''" @input="u(elem.name)"/>
			<select :name="elem.name" :disabled="!elem.options.length || elem.disabled" v-else-if="elem.type == 'select'" @change="selectActivator">
				<option :disabled="elem.placeholderDisabled" selected value="-1">{{ elem.placeholder }}</option>
				<option v-for="opt in elem.options" :value="opt.id ? opt.id : (opt.code ? opt.code : opt.name)">{{ opt.name }}</option>
			</select>
			<Multiselect v-else-if="elem.type == 'multiselect'" :options="elem.options" :placeholder="elem.placeholder || ''" :name="elem.name"/>
			<input type="reset" :value="elem.value" v-else-if="elem.type == 'reset'" @click="resetLists">
			<input type="submit" :value="elem.value" v-else-if="elem.type == 'submit'">
		</div>
	</form>
</template>

<script>
import Datepicker from 'vuejs-datepicker'
import {ru} from 'vuejs-datepicker/dist/locale'
import Multiselect from '@/components/multiselect'
export default {
	components: {Datepicker, Multiselect},

	props: {
		filterFields: Array,
		disableDate: Boolean
	},

	data() {
		return {
			ru: ru
		}
	},

	methods: {
		selectActivator(ev) {
			switch (ev.target.name) {
				// Выбрали клиента
				case 'client':
					this.$emit('clientChanged', ev.target.value)
					break

				// Выбрали волну
				case 'wave':
					this.$emit('waveChanged', ev.target.value)
					break

				case 'net':
					this.$emit('networkChanged', ev.target.value)
					break
			}
			this.u(ev)
		},

		resetLists() {
			this.$emit('reset')
		},

		submitForm(ev) {
			const data = {}
			Array.from(ev.target.querySelectorAll('[name]'))
			     .forEach(E => data[E.name] = E.value)

			this.$emit('submit', data)
		},

		// Отправка наверх текущего состояния фильтров
		u() {
			const data = {}

			this.$nextTick(() => {
				Array.from(document.querySelector('[data-filterform]').querySelectorAll('[name]'))
					 .forEach(E => data[E.name] = E.value)
	
				this.$emit('currentFilter', data)
			})
		}
	},

	watch: {
		// Если отключили даты, нужно обнулить поля с датами
		disableDate(Hide) {
			Hide && this.$nextTick(() => {
				Array.from(document.querySelectorAll('.filterBlock .vdp-datepicker input')).forEach(inp => inp.value = '')
			})
		}
	}
}
</script>

