<script>
import customInput from '@/components/input'
import Multiselect from '@/components/multiselect'
export default {
	props: {
		list: Array,
		type: String,
		subType: String,
		visibleFields: Object,
		segments: Array,
		producersSuggestions: {type: Object, default: () => { return {} }},
		headerFilters: Object,
		segmentsList: {type: Array, default: () => { return [] }},
		tradePointsList: {type: Array, default: () => { return [] }},
		netsList: {type: Array, default: () => { return [] }},
	},

	data() {
		return {
			selectedIDs: [],
			inHeaderFilters: {
				tradePoint: ''
			},
			
			sortField: '',
			sortingOrder: 'asc'
		}
	},

	mounted() {
		window.worker.addEventListener('message', this.workerHandler, false)
		Object.keys(this.headerFilters).forEach(K => {
			this.$set(this.inHeaderFilters, K, this.headerFilters[K])
		})
	},

	beforeDestroy() {
		window.worker.removeEventListener('message', this.workerHandler)
	},

	methods: {
		workerHandler(ev) {
			if ('type' in ev.data && ev.data.type == 'skuInfo' && ev.data.sku != undefined) {
				this.list[Number(ev.data.idx)].sku.brand    = ev.data.sku.brand
				this.list[Number(ev.data.idx)].sku.name     = ev.data.sku.name
				this.list[Number(ev.data.idx)].sku.producer = ev.data.sku.producer
				this.list[Number(ev.data.idx)].sku.segment  = ev.data.sku.segment
			}
		},

		// Забирает имя аудитора из объекта
		getAuditorName(auditorObj) {
			const nameParts = []
			auditorObj.first_name && nameParts.push(auditorObj.first_name)
			auditorObj.last_name && nameParts.push(auditorObj.last_name)
			if (nameParts.length)
				return nameParts.join(' ')

			return ''
		},

		// Забирает название сети из объекта
		getNetworkName(shopObj) {
			if (shopObj.retail_network && shopObj.retail_network.name)
				return shopObj.retail_network.name

			return ''
		},

		// Простановка выбранности для записи
		checkItem(idx, toggle) {
			if (toggle == undefined)
				this.list[idx].checked = true
			else
				this.list[idx].checked = !this.list[idx].checked

			this.$emit('check')
		},

		// Клик по картинке
		imgClick(idx) {
			this.$emit('imgClick', idx)
		},

		// Клик по имени для открытия подробностей
		showRecord(idx) {
			this.$emit('showDetails', idx)
		},

		// Значения для волн (массив преобразуется в строку через запятую)
		monitoring_wave(waves) {
			return waves.map(W => W.id).join(', ')
		},

		// Список клиентов
		clientsList(waves) {
			return waves.map(W => W.customer.name).join(', ')
		},

		// При изменении штрихкода остальные поля должны стать только для чтения
		readOnlyFields(item) {
			if (!item.sku) return true
			return item.sku.barcode != item.sku.srcBarcode
		},

		// Очистка значений sku
		clearItem(idx) {
			if (this.list[idx].sku.barcode != this.list[idx].sku.srcBarcode) {
				this.list[idx].sku.name     = ''
				this.list[idx].sku.brand    = ''
				this.list[idx].sku.producer = ''
			}
		},

		// Восстановление исходных значений sku
		restoreItem(idx) {
			this.list[idx].sku.barcode  = this.list[idx].sku.srcBarcode
			this.list[idx].sku.name     = this.list[idx].sku.srcName
			this.list[idx].sku.brand    = this.list[idx].sku.srcBrand
			this.list[idx].sku.producer = this.list[idx].sku.srcProducer
			this.list[idx].sku.segment  = this.list[idx].sku.srcSegment
		},

		// Загрузка данных sku по штрихкоду (при смене штрихкода)
		loadBarcode(idx) {
			if (this.list[idx].sku.barcode != this.list[idx].sku.srcBarcode) {
				this.clearItem(idx)
				window.worker.postMessage({
					type: 'getSku',
					token: this.token,
					barcode: this.list[idx].sku.barcode,
					idx: idx
				})
			}
			else this.restoreItem(idx)
		},

		// Событие, срабатывающее на нажатие кнопки "Подробно"
		moreButtonEvent(idx) {
			this.$emit('moreButtonPressed', idx)
		},

		// Событие смены бренда
		brandChanged(idx) {
			this.$emit('brandChanged', idx)
		},

		applyFilters() {
			this.$emit('applyFilters')
		},

		applyMultiselect(name, values) {
			this.inHeaderFilters[name] = values
			this.applyFilters()
		},

		// Установка сортировки по полю
		setSort(field) {
			if (field == this.sortField) {
				if (this.sortingOrder == 'desc') {
					this.sortField = ''
					this.sortingOrder = 'asc'
				}
				else
					this.sortingOrder = 'desc'
			}
			else {
				this.sortField = field
				this.sortingOrder = 'asc'
			}

			const result = this.sortField.length ? `${this.sortField}_${this.sortingOrder}` : ''
			this.$emit('sortingChange', result)
		}
	},

	computed: {
		disablePrices() {
			return this.subType == 'toclient' || this.subType == 'deleted'
		},

		// true, если все поля таблицы должны быть редактируемыми
		allFieldsAreInputs() {
			return this.subType == 'noitem'
		},

		segmentsList_sorted() {
			return this.segmentsList.sort((A, B) => A < B)
		}
	},

	watch: {
		// Если меняется заголовочный фильтр, отправляем его наверх
		inHeaderFilters(value) {
			this.$emit('headerFilterChanged', value)
		}
	},

	components: {
		customInput,
		Multiselect
	}
}
</script>

