<template>
	<div class="wrapper">
		<div class="rotator">
			<img src="@/assets/img/rotate.svg" alt="повернуть" class="mirrored" @click="rotateLeft" title="Поворот влево">
			<img src="@/assets/img/rotate.svg" alt="повернуть" @click="rotateRight" title="Поворот вправо">
		</div>
		<div :class="{imgContainer: true, fullSize: originalSize}" ref="cnt">
			<canvas ref="canvas" @click="sendClick" @mousedown="mousedown" @mouseup="mouseup" @mousemove="mousemove"></canvas>
		</div>
	</div>
</template>

<script>
	export default {
		props: {src: String},
		data() {
			return {
				rotate: 0,    //Угол поворота
				size: {
					w: 0,
					h: 0
				},
				img: null,
				canvas: null,

				originalSize: false,
			}
		},

		mounted() {
			this.canvas = this.$refs.canvas

			this.img = new Image()
			this.img.src = this.src
			this.img.onload = () => {
				this.size.w = this.img.width
				this.size.h = this.img.height

				setTimeout(this.drawImageOnCanvas, 200)
			},
			this.$refs.cnt.style.maxHeight = getComputedStyle(this.$refs.cnt).height
			this.$refs.cnt.style.maxWidth = getComputedStyle(this.$refs.cnt).width
		},

		methods: {
			sendClick(e) {
				this.originalSize = !this.originalSize
				if (this.originalSize) {
					const CR = this.$refs.canvas.getBoundingClientRect()
					this.$nextTick(() => {
						const C = this.$refs.cnt 
						C.scrollLeft = (C.scrollWidth - parseInt(getComputedStyle(C).width)) * (e.clientX - CR.left) / CR.width  
						C.scrollTop =  (C.scrollHeight - parseInt(getComputedStyle(C).height)) * (e.clientY - CR.top) / CR.height
					})
				}

				this.drawImageOnCanvas()

				//this.$emit('click', e)
			},

			rotateLeft() {
				this.rotate = this.rotate < -180 ? 0 : this.rotate - 90
			},

			rotateRight() {
				this.rotate = this.rotate > 180 ? 0 : this.rotate + 90
			},

			drawImageOnCanvas() {
				const cx = this.canvas.getContext('2d')
				const rotated = Math.abs(this.rotate) == 90 || Math.abs(this.rotate) == 270
				const blockWidth = parseInt(getComputedStyle(this.$refs.cnt).width)
				const blockHeight = parseInt(getComputedStyle(this.$refs.cnt).height)  // Приходится хардкодить. Это же значение есть в CSS
				const imgW = rotated ? this.size.h : this.size.w
				const imgH = rotated ? this.size.w : this.size.h

				// Соотношение сторон блок с картинкой, по нему будем решать, какой стороной вписывать картинку
				const blockAspect = blockWidth / blockHeight
				let imgAspect = this.size.w / this.size.h
				if (rotated) imgAspect = 1 / imgAspect

				let h, w

				// Вписываем картинку в маленький блок
				if (!this.originalSize) {
					// Сперва вариант, когда картинка шире родительского блока или как раз равна
					if (imgAspect >= blockAspect) {
						w = blockWidth
						h = parseInt(w / imgW * imgH)
					}
					// Если картинка выше родительского блока, а по ширине умещается
					else {
						h = blockHeight
						w = parseInt(h / imgH * imgW)
					}
				}
				// Оставляем картинку исходного размера
				else {
					w = imgW
					h = imgH
				}

				this.canvas.style.width = w + 'px'
				this.canvas.style.height = h + 'px'

				this.canvas.width = w
				this.canvas.height = h

				if (this.rotate !== 0) {
					if (this.rotate === 90 || this.rotate === -270)
						cx.translate(w , 0)
					else if (Math.abs(this.rotate) == 180)
						cx.translate(w , h)
					else if (this.rotate == -90 || this.rotate === 270)
						cx.translate(0 , h)

					cx.rotate(this.rotate * Math.PI / 180)
				}

				if (rotated) cx.drawImage(this.img, 0, 0, h, w)
				else cx.drawImage(this.img, 0, 0, w, h)
			},

			mousedown() {
				// На будущее
			},

			mouseup() {
				// На будущее
			},

			mousemove() {
				// На будущее
			}
		},

		watch: {
			rotate() {
				this.drawImageOnCanvas()
			}
		}
	}
</script>

<style lang="scss" scoped>
	.rotator {
		margin: 4px 0 2px;
		text-align: center;
		font-size: 0;
		-moz-user-select: none;
		user-select: none;

		img {
			display: inline-block;
			cursor: pointer;
			width: 24px;
			height: 24px;

			&:first-child { margin-right: 16px; }
		}

		.mirrored { transform: scaleX(-1); }
	}

	.wrapper {
		width: 96%;
		max-width: 96%;
		font-size: 0;
		justify-self: center;
		display: grid;
		grid-template-rows: 30px 1fr;
		grid-template-columns: 100%;
	}

	.imgContainer {
		width: 100%;
		max-width: 100%;
		overflow: auto;
		display: grid;
		grid-template-rows: 100%;
		grid-template-columns: 100%;

		canvas {
			width: 100%;
			height: 10px;
			cursor: pointer;
			justify-self: center;
		}
		
		&.fullSize canvas { justify-self: start; }
	}
</style>