import Vue from 'vue'
import Vuex from 'vuex'
import userHasRole from './fn_userHasRole'

Vue.use(Vuex)

export default new Vuex.Store({
	state: {
		token: null,
		userRoles: [],    // Роли пользователя
		userName: '--',
		userId: null,
		lastPage: ''
	},
	actions: {
		// Метод для доставания токена ил localStorage
		setToken(vx, token) {
			if (token && token.length)
				vx.state.token = token
		},
		setNewToken(vx, token) {
			vx.state.token = token
			localStorage.setItem('token', token)
		},
		deleteToken(vx) {
			vx.state.token = null
			localStorage.removeItem('token')
		},

		setUserData(vx, userData) {
			if (userData) {
				const fullName = `${userData.first_name} ${userData.last_name}`
				vx.state.userName = (fullName == ' ' ? userData.username : fullName)

				vx.state.userRoles = []
				if (userData.groups && userData.groups.length)
					userData.groups.forEach(role => vx.state.userRoles.push(role.name))

				vx.state.userId = userData.id
			}
		},
		// Нужно вызывать при логауте
		clearUserData(vx) {
			vx.state.userRoles = []
			vx.state.userName = ''
		},

		setLastPage(vx, page) {
			vx.state.lastPage = page
		}
	},
	getters: {
		getToken:     st => st.token,
		getUserRoles: st => st.userRoles,
		getUserName:  st => st.userName,
		getLastPage:  st => st.lastPage,
		getUserId:    st => st.userId,

		// Ссылки меню, которые нужно отображать или скрывать
		linksToDraw: st => {
			return {
				records: userHasRole(st.userRoles, ['auditor', 'mentor', 'coordinator']),
				sku:     userHasRole(st.userRoles, ['coordinator']),
				charts:  userHasRole(st.userRoles, ['mentor', 'coordinator']),
				waves:   userHasRole(st.userRoles, ['mentor', 'admin']),
				users:   userHasRole(st.userRoles, ['mentor', 'admin']),
				prices:  userHasRole(st.userRoles, 'admin'),
				chat:    true
			}
		}
	}
})