<template>
	<div class="priceblock">
		<h4>{{ Title }}</h4>
		<input type="text" :name="name" v-model="Value" @input="change" :class="{blocked: blocked, old: old}" :disabled="blocked || old" @keyup="keyup">
	</div>
</template>

<script>
export default {
	props: ['title', 'value', 'old', 'blocked', 'name', 'hideTitle'],
	data() {
		return {
			Value: 0
		}
	},

	created() {
		this.Value = this.value || ''
	},

	methods: {
		change() {
			this.$emit('input', this.valueNumber)
		},
		
		keyup(ev) {
			this.$emit('keyup', ev)
		}
	},

	computed: {
		valueNumber() {
			const ret = this.Value.toString()
				.replace(/[^0-9.,]/, '')
				.replace(',', '.')
				.replace(/\.(\d\d).+$/, '.$1')
				.replace(/^(\d*?\.\d*?)\..*$/, '$1')
			
			this.Value = ret

			return ret
		},
		
		Title() {
			return this.hideTitle ? '' : this.title
		}
	},

	watch: {
		value(V) {
			this.Value = V
		}
	}
}
</script>

