<template>
	<!-- ctrl+alt+"\" обновляет записи -->
	<div class="body">
		<div class="header">Чат</div>
		<div class="filterline">
			
		</div>
	</div>
</template>

<script>
import pager from '@/components/pager'
import filterBlock from '@/components/filterBlock'
export default {
	components: {pager, filterBlock},
	created() {
		this.clearFilters('init')
		this.$store.dispatch('setLastPage', this.type)
	},

	data() {
		return {
			type: 'users',
			page: 1,
			users: [],
			filters: null,

			filterFields: [
				{
					type: 'input',
					name: 'lastName',
					placeholder: 'Поиск по фамилии',
					width: 2,
					row: 1
				},
				{
					type: 'input',
					name: 'lastName',
					placeholder: 'Поиск по логину',
					width: 2,
					row: 1
				},
				{
					type: 'reset',
					value: 'Очистить фильтры',
					width: 2,
					row: 1
				},
				{
					type: 'submit',
					value: 'Применить',
					width: 2,
					row: 1
				}
			]
		}
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))

		if (!this.uRoles.length || !this.linksToDraw[this.type]) {
			location.hash = '#/splash'
			return
		}

		this.refreshList()

		window.addEventListener('keyup', this.keyHandler, false)
		window.worker.addEventListener('message', this.workerHandler)
	},

	beforeDestroy() {
		window.removeEventListener('keyup', this.keyHandler)
		window.worker.removeEventListener('message', this.workerHandler)
	},

	methods: {
		keyHandler(E) {
			if (E.code == 'F2' && !E.ctrlKey && !E.altKey)
				this.saveChanges()
		},

		workerHandler(ev) {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				case 'allas':

					break
			}
		},

		refreshList() {
			if (this.token) {
				this.users = []

				window.worker.postMessage({
					type: this.type,
					page: this.page,
					pageSize: this.pageSize,
					token: this.token,
					filters: this.filters
				})
			}
		},

		clearFilters(init) {
			this.filters = {
				lastName: '',
				login:    ''
			}

			if (init == undefined)
				this.refreshList()
		}
	},

	watch: {
		uRoles(newRoles, oldRoles) {
			if (!newRoles.length) return

			if (newRoles.length && !this.linksToDraw[this.type]) {
				location.hash = '#/splash'
				return
			}

			if (!oldRoles.length)
				this.refreshList()
		},

		token(newToken) {
			if (newToken !== null && this.uRoles.length && this.refreshList)
				this.refreshList()
		},

		page() {
			this.refreshList()
		}
	}
}
</script>

