<template>
	<progress></progress>
</template>

<script>
export default {
	mounted() {
		if (this.uRoles.length) {
			const nextPage = this.gotoFirstMenuEntry()
			location.hash = `#/${nextPage}`
		}
	},

	watch: {
		uRoles(newRoles) {
			if (!newRoles.length) return

			const nextPage = this.gotoFirstMenuEntry()
			location.hash = `#/${nextPage}`
		}
	}
}
</script>

