<template>
	<a href="" class="multiselect_wrapper" @click.prevent="" @blur="emitChange">
		<div :class="{selected_values: true, empty: !selected.length || !options.length}">{{ selectedText }}</div>
		<span class="triangle"></span>
		<ul :class="{hidden: !options.length}">
			<li v-for="option in options" @click="checkOption(option.id)" :class="{checked: selected.indexOf(option.id) !== -1}"><mark></mark> {{ option.name }}</li>
		</ul>
		<input type="hidden" :name="name" :value="selected.join(',')">
	</a>
</template>

<script>
	export default {
		props: {
			options: Array,
			placeholder: String,
			name: String,
			single: {type: Boolean, default: false}
		},

		data() {
			return {
				selected: [],
				needUpdate: false,  // Флаг того, что были изменения, чтобы при каждом блюре не обновлять фильтр

				loadingText: '----.',
				loadingInterval: null
			}
		},

		created() {
			this.loadingInterval = setInterval(() => {
				let M = this.loadingText.split('')
				this.loadingText = M.pop() + M.join('')
			}, 500)
		},

		beforeDestroy() {
			if (this.loadingInterval)
				clearInterval(this.loadingInterval)
		},

		computed: {
			selectedText() {
				if (!this.options.length) return this.loadingText
				return this.selected.length && this.options.length ? (this.selected.length == 1 ? this.options.filter(F => F.id == this.selected[0])[0].name : `Выбрано: ${this.selected.length}`) : this.placeholder
			}
		},

		methods: {
			emitChange() {
				if (!this.needUpdate) return

				this.needUpdate = false
				this.$emit('multichange', this.selected.join(','))
			},

			checkOption(id) {
				this.needUpdate = true
				const idx = this.selected.indexOf(id)
				
				if (idx !== -1)
					this.$delete(this.selected, idx)
				else {
					if (this.single)
						this.selected = [id]
					else
						this.selected.push(id)
				}
			}
		},

		watch: {
			options(opt) {
				if (!opt.length)
					this.selected = []
			}
		}
	}
</script>

