<template>
	<div class="tabLine">
		<span :class="{tab: true, active: activeTab == tab.name}" v-for="tab in tabs" @click="tabSelect(tab.name)">
			{{ tab.value }}
		</span>
	</div>
</template>

<script>
export default {
	props: {
		tabs: Array,
		initialTab: String
	},

	data() {
		return {
			activeTab: ''
		}
	},

	mounted() {
		this.activeTab = this.initialTab
	},

	methods: {
		tabSelect(tab) {
			this.activeTab = tab
			this.$emit('change', tab)
		}
	}
}
</script>

