export default {
	data() {
		return {
			pageSize: 20
		}
	},

	mounted() {
		return {}
	},

	computed: {
		linksToDraw() { return this.$store.getters.linksToDraw },
		token() { return this.$store.getters.getToken },
		uRoles() { return this.$store.getters.getUserRoles },
		/* /linksPrefix() { return 'http://91.218.229.81:8000/' }
		/*/ linksPrefix() { return 'http://116.203.39.144:8000/' }
