	methods: {
		hasOnlyRole(role) {
			const uRoles = this.$store.getters.getUserRoles
			return uRoles.length == 1 && userHasRole(uRoles, role)
		},

		convertDate(date) {
			if (date === undefined) return ''
			const D = new Date(date.replace(/\+(\d{2})(\d{2})$/, '+$1:$2'))
			let M = 1 + D.getMonth()
			if (M < 10) M = `0${M}`
			let F = D.getDate()
			if (F < 10) F = `0${F}`

			return `${F}.${M}.${D.getFullYear()}`
		},

		// Переход к последней посещённой странице или к первому пункту меню из доступных
		gotoFirstMenuEntry() {
			let menu = null
			const lastPage = this.$store.getters.getLastPage

			if (this.linksToDraw[lastPage])
				return lastPage

			Object.getOwnPropertyNames(this.linksToDraw).forEach(E => {
				if (menu !== null) return

				if (this.linksToDraw[E])
					menu = E
			})

			return menu
		},

		// Показ или скрытие процентов с добавлением значка %
		drawPercent(sum) {
			return (sum != 0) ? sum + '%' : ''
		},

		calcAuchanPercent(item) {
			const ret = this.drawPercent(item.average_diff_percent)
			
			return ret
			/*let price = ''

			if (item.sku && item.sku.average_price)
				price = `<mark>${Number(item.sku.average_price)} ₽</mark>`

			if (!ret) return price
			return ret + price*/
		}
	}
}
</script>