<template>
	<div class="pager">
		<span :class="{arrow: true, left:true, page:true, disabled: currentPage == 1}" @click="goto(currentPage-1)" title="Предыдущая [ctrl + ←]"></span>
		<span class="page np" v-if="currentPage > 3">…</span>
		<span :class="{page: true, active: currentPage == idx}" v-for="idx in visiblePages" @click="goto(idx)">{{ idx }}</span>
		<span class="page dots" v-if="currentPage < pagesCount - 2">…</span>
		<span :class="{arrow: true, right:true, page:true, disabled: currentPage == pagesCount}" @click="goto(currentPage+1)" title="Следующая [ctrl + →]"></span>
	</div>
</template>

<script>
export default {
	props: {
		currentPage: Number,
		pagesCount: Number
	},

	data() {
		return {}
	},

	computed: {
		visiblePages() {
			const ret = []

			for (let Z = Math.max(this.currentPage - 2, 1); Z <= Math.min(this.pagesCount, this.currentPage + 2); ++Z)
				ret.push(Z)

			return ret
		}
	},

	methods: {
		goto(page) {
			this.$emit('changePage', page)
		}
	}
}
</script>

<style lang="scss" scoped>
	.arrow {
		display: inline-block;
		width: 34px;
		height: 10px;
		background: center 0 url('../assets/img/pager_arrow.svg') no-repeat;
		cursor: pointer;

		&.left { transform: rotate(180deg); }
		&.disabled {
			filter: contrast(10%) brightness(130%);
			pointer-events: none;
		}
		&:not(.disabled):hover {
			filter: invert(30%) sepia(100%) saturate(600%) hue-rotate(170deg) brightness(150%);
		}
	}

	.page {
		padding: 0 8px;
		cursor: pointer;
		font-size: 16px;
		user-select: none;

		&.dots  { cursor: auto; }
		&.active {
			color: var(--blueColor);
			font-weight: bold;
			cursor: auto;
			pointer-events: none;
		}

		&:not(.active):not(.dots):hover {
			color: var(--blueColor);
		}
	}
</style>