<template>
	<div class="body">
		<div class="header">Аналитика</div>
		<div class="filterline" v-if="hasOnlyRole('coordinator')">
			<filterBlock :filterFields="filterFields" @reset="clearFilters" @submit="setFilter" @currentFilter="setFiltersValues"/>
		</div>
		<div class="buttons" v-if="hasOnlyRole('coordinator')">
			<input type="button" value="Аудиторы"  :disabled="!isFilterFilled" @click="exportFile('auditor')">
			<input type="button" value="Новинки"   :disabled="!isFilterFilled" @click="exportFile('novelties')">
			<input type="button" value="Сегменты"  :disabled="!isFilterFilled" @click="exportFile('segment')">
			<input type="button" value="Модерация" :disabled="!isFilterFilled" @click="exportFile('moderation')">
		</div>
		<div class="exportLinks" v-if="exportLinks.length || pendingExport">
			<div v-if="exportLinks.length">Экспортированные файлы</div>
			<div class="links" v-if="exportLinks.length">
				<a v-for="link in exportLinks" :href="linksPrefix + link">{{ link.replace(/^.+\//, '') }}</a>
			</div>
			<progress v-if="pendingExport"></progress>
			<button v-if="exportLinks.length" @click="exportLinks = []">Скрыть ссылки</button>
		</div>
		<div class="overlay lock" v-if="pendingExport"></div>
	</div>
</template>

<script>
import pager from '@/components/pager'
import filterBlock from '@/components/filterBlock'
export default {
	components: {pager, filterBlock},
	created() {
		this.clearFilters('init')
		this.$store.dispatch('setLastPage', this.type)
	},

	data() {
		return {
			type: 'charts',
			filters: null,
			wavesList: {},
			filtersValues: {},
			pendingExport: false,
			exportLinks: []
		}
	},

	mounted() {
		if (localStorage.getItem('token'))
			this.$store.dispatch('setToken', localStorage.getItem('token'))

		if (!this.uRoles.length || !this.linksToDraw[this.type]) {
			location.hash = '#/splash'
			return
		}

		window.worker.postMessage({
			type: 'wavesFilter',
			token: this.token,
			client: -1
		})

		window.addEventListener('keyup', this.keyHandler, false)
		window.worker.addEventListener('message', this.workerHandler)
	},

	beforeDestroy() {
		window.removeEventListener('keyup', this.keyHandler)
		window.worker.removeEventListener('message', this.workerHandler)
	},

	methods: {
		workerHandler(ev) {
			if (!('type' in ev.data)) return

			switch (ev.data.type) {
				case 'wavesFilter':
					this.wavesList = ev.data.waves
					break

				case 'badExport':
					this.pendingExport = false
					break

				case 'exportDone':
					this.pendingExport = false
					if (!ev.data.link || !ev.data.link.file)
						alert('Сервер вернул пустой список выгрузки')
					else
						this.exportLinks.push(ev.data.link.file)
					break
			}
		},

		clearFilters(init) {
			this.filters = {
				dateFrom: '',
				dateTo:   '',
				wave:     -1
			}

			this.filtersValues = {}
		},

		setFilter(data) {
			this.filters = Object.assign(this.filters, data)
		},

		setFiltersValues(data) {
			this.filtersValues = data
		},

		exportFile(exportType) {
			if (this.isFilterFilled) {
				this.pendingExport = true

				window.worker.postMessage({
					type: 'statistics',
					statType: exportType,
					token: this.token,
					filters: this.filtersValues
				})
			}
		}
	},

	watch: {
		uRoles(newRoles, oldRoles) {
			if (!newRoles.length) return

			if (newRoles.length && !this.linksToDraw[this.type]) {
				location.hash = '#/splash'
				return
			}
		}
	},

	computed: {
		filterFields() {
			return [
				{
					type: 'date',
					name: 'dateFrom',
					placeholder: 'Дата с',
					row: 1
				},
				{
					type: 'date',
					name: 'dateTo',
					placeholder: 'Дата до',
					row: 1
				},
				{
					type: 'select',
					name: 'wave',
					placeholder: 'Волна',
					row: 1,
					options: this.wavesList,
					placeholderDisabled: true
				},
				{
					type: 'reset',
					value: 'Очистить фильтры',
					width: 2,
					row: 1
				}
			]
		},

		isFilterFilled() {
			return this.filtersValues.dateFrom && this.filtersValues.dateFrom.length
			       && this.filtersValues.dateTo && this.filtersValues.dateTo.length
			       && this.filtersValues.wave && this.filtersValues.wave != -1
		}
	}
}
</script>

