// Определяет, присутствует ли у пользователя хоть одна из ролей

const rolesList = {
	auditor:     'Аудитор',
	mentor:      'Наставник',
	coordinator: 'Координатор',
	admin:       'Администратор'
}

// В первом параметре список ролей пользвоателя, во втором — список ролей, хотя бы одну из которых мы ищем
function userHasRole(userRoles, roles) {
	if (userRoles.constructor.name != 'Array')
		userRoles = [userRoles]

	if (roles.constructor.name != 'Array')
		roles = [roles]

	if (!userRoles.length) return false

	return roles.some(role => userRoles.includes(rolesList[role]))
}

export {userHasRole as default, rolesList}